package com.eagle.app.auth;

import com.eagle.app.model.Role;
import com.eagle.app.model.RoleName;
import com.eagle.app.model.User;
import com.eagle.app.repository.RoleRepository;
import com.eagle.app.repository.UserRepository;
import com.eagle.app.security.JwtService;
import org.springframework.security.authentication.BadCredentialsException;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Set;

@Service
public class AuthService {

    private static final int MAX_FAILED_ATTEMPTS = 5;

    private final UserRepository userRepository;
    private final RoleRepository roleRepository;
    private final PasswordEncoder passwordEncoder;
    private final JwtService jwtService;

    public AuthService(UserRepository userRepository,
                       RoleRepository roleRepository,
                       PasswordEncoder passwordEncoder,
                       JwtService jwtService) {
        this.userRepository = userRepository;
        this.roleRepository = roleRepository;
        this.passwordEncoder = passwordEncoder;
        this.jwtService = jwtService;
    }

    @Transactional
    public void register(RegisterRequest request) {
        if (userRepository.existsByUsername(request.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(request.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }

        Role requesterRole = roleRepository.findByName(RoleName.REQUESTER)
                .orElseThrow(() -> new IllegalStateException("REQUESTER role missing"));

        User user = new User();
        user.setUsername(request.getUsername());
        user.setEmail(request.getEmail());
        user.setPasswordHash(passwordEncoder.encode(request.getPassword()));
        user.setStaffContactInfo(request.getStaffContactInfo());
        user.setRoles(Set.of(requesterRole));
        userRepository.save(user);
    }

    @Transactional
    public AuthResponse login(LoginRequest request) {
        User user = userRepository.findByUsername(request.getUsername())
                .orElseThrow(() -> new BadCredentialsException("Invalid credentials"));

        if (isLocked(user)) {
            throw new BadCredentialsException("Account is locked until " + user.getLockUntil());
        }

        if (!passwordEncoder.matches(request.getPassword(), user.getPasswordHash())) {
            registerFailedAttempt(user);
            throw new BadCredentialsException("Invalid credentials");
        }

        user.setFailedAttempts(0);
        user.setLockUntil(null);
        userRepository.save(user);

        return new AuthResponse(jwtService.generateToken(user));
    }

    private boolean isLocked(User user) {
        return user.getLockUntil() != null && user.getLockUntil().isAfter(Instant.now());
    }

    private void registerFailedAttempt(User user) {
        int failed = user.getFailedAttempts() + 1;
        user.setFailedAttempts(failed);
        if (failed >= MAX_FAILED_ATTEMPTS) {
            user.setFailedAttempts(0);
            user.setLockUntil(Instant.now().plus(15, ChronoUnit.MINUTES));
        }
        userRepository.save(user);
    }
}
