package com.eagle.app.service;

import com.eagle.app.exception.InvalidStateTransitionException;
import com.eagle.app.model.Asset;
import com.eagle.app.model.AssetLifecycleState;
import com.eagle.app.model.AssetOperationalStatus;
import com.eagle.app.repository.AssetRepository;
import org.springframework.context.ApplicationEventPublisher;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Set;

@Service
public class AssetService {

    private final AssetRepository assetRepository;
    private final ApplicationEventPublisher eventPublisher;

    public AssetService(AssetRepository assetRepository, ApplicationEventPublisher eventPublisher) {
        this.assetRepository = assetRepository;
        this.eventPublisher = eventPublisher;
    }

    @Transactional
    public Asset updateOperationalStatus(Long assetId, AssetOperationalStatus newStatus) {
        Asset asset = assetRepository.findById(assetId)
                .orElseThrow(() -> new IllegalArgumentException("Asset not found"));
        AssetOperationalStatus oldStatus = asset.getOperationalStatus();
        asset.setOperationalStatus(newStatus);
        Asset saved = assetRepository.save(asset);

        eventPublisher.publishEvent(new AssetStatusChangedEvent(
                saved.getId(),
                saved.getRoom().getId(),
                saved.isEssential(),
                oldStatus,
                newStatus
        ));
        return saved;
    }

    @Transactional
    public Asset transitionLifecycle(Long assetId, AssetLifecycleState target) {
        Asset asset = assetRepository.findById(assetId)
                .orElseThrow(() -> new IllegalArgumentException("Asset not found"));

        AssetLifecycleState current = asset.getLifecycleState();
        if (!isValidTransition(current, target)) {
            throw new InvalidStateTransitionException("Invalid asset lifecycle transition: " + current + " -> " + target);
        }
        asset.setLifecycleState(target);
        return assetRepository.save(asset);
    }

    private boolean isValidTransition(AssetLifecycleState current, AssetLifecycleState target) {
        if (current == target) {
            return true;
        }
        return switch (current) {
            case NORMAL -> Set.of(AssetLifecycleState.UNDER_REPAIR).contains(target);
            case UNDER_REPAIR -> Set.of(AssetLifecycleState.NORMAL, AssetLifecycleState.RETIRED).contains(target);
            case RETIRED -> false;
        };
    }
}
