        this.warningAlternativeService = warningAlternativeService;
    }

    @TransactionalEventListener
    public void onAssetStatusChanged(AssetStatusChangedEvent event) {
        if (!event.essential() || event.oldStatus() == event.newStatus()) {
            return;
        }

        Room room = roomRepository.findById(event.roomId())
                .orElseThrow(() -> new IllegalArgumentException("Room not found for asset event"));

        if (event.newStatus() == AssetOperationalStatus.OUT_OF_SERVICE) {
            room.setReservable(false);
            room.setReservationWarning(warningAlternativeService.buildWarningAndAlternatives(room));
        } else {
            room.setReservable(true);
            room.setReservationWarning(null);
        }

        roomRepository.save(room);
    }
}
