package com.eagle.app.service;

import com.eagle.app.model.MaintenanceTicket;
import com.eagle.app.repository.MaintenanceTicketRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.DayOfWeek;
import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.time.ZoneOffset;

@Service
public class MaintenanceSlaService {

    private static final LocalTime BUSINESS_START = LocalTime.of(9, 0);
    private static final LocalTime BUSINESS_END = LocalTime.of(17, 0);
    private static final long SLA_BUSINESS_MINUTES = 4 * 60;

    private final MaintenanceTicketRepository maintenanceTicketRepository;

    public MaintenanceSlaService(MaintenanceTicketRepository maintenanceTicketRepository) {
        this.maintenanceTicketRepository = maintenanceTicketRepository;
    }

    @Transactional
    public MaintenanceTicket recordInitialResponse(Long ticketId, Instant responseTime) {
        MaintenanceTicket ticket = maintenanceTicketRepository.findById(ticketId)
                .orElseThrow(() -> new IllegalArgumentException("Ticket not found"));

        ticket.setInitialResponseAt(responseTime);
        long businessMinutes = businessMinutesBetween(ticket.getCreatedAt(), responseTime);
        ticket.setSlaBreached(businessMinutes > SLA_BUSINESS_MINUTES);

        return maintenanceTicketRepository.save(ticket);
    }

    long businessMinutesBetween(Instant start, Instant end) {
        if (end.isBefore(start)) {
            return 0;
        }

        LocalDateTime cursor = LocalDateTime.ofInstant(start, ZoneOffset.UTC);
        LocalDateTime endDateTime = LocalDateTime.ofInstant(end, ZoneOffset.UTC);
        long totalMinutes = 0;

        while (!cursor.toLocalDate().isAfter(endDateTime.toLocalDate())) {
            LocalDate day = cursor.toLocalDate();
            if (isBusinessDay(day.getDayOfWeek())) {
                LocalDateTime windowStart = LocalDateTime.of(day, BUSINESS_START);
                LocalDateTime windowEnd = LocalDateTime.of(day, BUSINESS_END);

                LocalDateTime actualStart = max(cursor, windowStart);
                LocalDateTime actualEnd = min(endDateTime, windowEnd);

                if (actualEnd.isAfter(actualStart)) {
                    totalMinutes += java.time.Duration.between(actualStart, actualEnd).toMinutes();
                }
            }
            cursor = LocalDateTime.of(cursor.toLocalDate().plusDays(1), LocalTime.MIDNIGHT);
        }

        return totalMinutes;
    }

    private boolean isBusinessDay(DayOfWeek day) {
        return day != DayOfWeek.SATURDAY && day != DayOfWeek.SUNDAY;
    }

    private LocalDateTime max(LocalDateTime a, LocalDateTime b) {
        return a.isAfter(b) ? a : b;
    }

    private LocalDateTime min(LocalDateTime a, LocalDateTime b) {
        return a.isBefore(b) ? a : b;
    }
}
