package com.eagle.app.service;

import com.eagle.app.exception.ChecksumValidationException;
import com.eagle.app.exception.DuplicateEntryException;
import com.eagle.app.model.ChecksumAlgorithm;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.HexFormat;
import java.util.List;
import java.util.Map;

@Service
public class CsvReconciliationService {

    private static final DateTimeFormatter DATE_FORMATTER = DateTimeFormatter.ofPattern("MM/dd/yyyy");

    public CsvReconciliationResult reconcile(String csvContent,
                                             ChecksumAlgorithm algorithm,
                                             String expectedChecksum,
                                             boolean failOnDuplicates) {
        String computed = computeChecksum(csvContent, algorithm);
        if (!computed.equalsIgnoreCase(expectedChecksum)) {
            throw new ChecksumValidationException("Checksum mismatch for CSV statement payload");
        }

        List<BankStatementEntry> entries = parse(csvContent);
        List<BankStatementEntry> duplicates = findDuplicates(entries);

        if (failOnDuplicates && !duplicates.isEmpty()) {
            throw new DuplicateEntryException("Duplicate statement entries detected");
        }

        return new CsvReconciliationResult(true, entries, duplicates);
    }

    public String computeChecksum(String payload, ChecksumAlgorithm algorithm) {
        try {
            MessageDigest digest = MessageDigest.getInstance(algorithm == ChecksumAlgorithm.MD5 ? "MD5" : "SHA-256");
            return HexFormat.of().formatHex(digest.digest(payload.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception ex) {
            throw new IllegalStateException("Unable to compute checksum", ex);
        }
    }

    private List<BankStatementEntry> parse(String csvContent) {
        String[] lines = csvContent.split("\\r?\\n");
        List<BankStatementEntry> entries = new ArrayList<>();

        for (int i = 1; i < lines.length; i++) {
            String line = lines[i].trim();
            if (line.isEmpty()) {
                continue;
            }
            String[] parts = line.split(",");
            LocalDate bookingDate = LocalDate.parse(parts[0].trim(), DATE_FORMATTER);
            String reference = parts[1].trim();
            BigDecimal amount = new BigDecimal(parts[2].trim());
            BigDecimal balance = new BigDecimal(parts[3].trim());
            entries.add(new BankStatementEntry(bookingDate, reference, amount, balance));
        }

        return entries;
    }

    private List<BankStatementEntry> findDuplicates(List<BankStatementEntry> entries) {
        Map<String, Integer> seen = new HashMap<>();
        List<BankStatementEntry> duplicates = new ArrayList<>();

        for (BankStatementEntry entry : entries) {
            String key = entry.bookingDate() + "|" + entry.reference() + "|" + entry.amount();
            int count = seen.getOrDefault(key, 0) + 1;
            seen.put(key, count);
            if (count > 1) {
                duplicates.add(entry);
            }
        }

        return duplicates;
    }
}
