package com.eagle.app.service;

import com.eagle.app.exception.ReservationConflictException;
import com.eagle.app.model.Reservation;
import com.eagle.app.model.Room;
import com.eagle.app.repository.ReservationRepository;
import com.eagle.app.repository.RoomRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class ReservationService {

    private final ReservationRepository reservationRepository;
    private final RoomRepository roomRepository;

    public ReservationService(ReservationRepository reservationRepository, RoomRepository roomRepository) {
        this.reservationRepository = reservationRepository;
        this.roomRepository = roomRepository;
    }

    @Transactional
    public Reservation createReservation(Reservation reservation) {
        validateRoomAvailability(reservation.getRoom().getId());
        validateNoConflict(reservation);
        return reservationRepository.save(reservation);
    }

    public void validateNoConflict(Reservation reservation) {
        long conflicts = reservationRepository.countConflicts(
                reservation.getRoom().getId(),
                reservation.getStartTime(),
                reservation.getEndTime()
        );
        if (conflicts > 0) {
            throw new ReservationConflictException("Room has a conflicting reservation in the selected minute range");
        }
    }

    public void validateRoomAvailability(Long roomId) {
        Room room = roomRepository.findById(roomId)
                .orElseThrow(() -> new IllegalArgumentException("Room not found"));
        if (!room.isReservable()) {
            throw new ReservationConflictException(
                    room.getReservationWarning() != null ? room.getReservationWarning() : "Room is non-reservable"
            );
        }
    }
}

