package com.eagle.app.service;

import com.eagle.app.model.AuditAction;
import com.eagle.app.model.AuditLog;
import com.eagle.app.model.User;
import com.eagle.app.repository.AuditLogRepository;
import com.eagle.app.repository.UserRepository;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class AuditService {

    private final AuditLogRepository auditLogRepository;
    private final UserRepository userRepository;

    public AuditService(AuditLogRepository auditLogRepository, UserRepository userRepository) {
        this.auditLogRepository = auditLogRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public void write(AuditAction action, String entityType, String entityRef, String details) {
        AuditLog log = new AuditLog();
        log.setAction(action);
        log.setEntityType(entityType);
        log.setEntityRef(entityRef);
        log.setDetails(details);
        log.setActor(resolveActor());
        auditLogRepository.save(log);
    }

