package com.eagle.app.service;

import com.eagle.app.security.EncryptionKeyProvider;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;

import javax.crypto.Cipher;
import javax.crypto.SecretKey;
import javax.crypto.spec.GCMParameterSpec;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.security.SecureRandom;
import java.time.Instant;

@Service
public class BackupService {

    private static final int IV_LENGTH = 12;
    private static final int TAG_BITS = 128;

    @Value("${app.backup.directory}")
    private String backupDirectory;

    @Value("${DB_HOST:localhost}")
    private String dbHost;

    @Value("${DB_PORT:5432}")
    private String dbPort;

    @Value("${DB_NAME:eagle}")
    private String dbName;

    @Value("${DB_USER:eagle}")
    private String dbUser;

    @Value("${DB_PASSWORD:eaglepass}")
    private String dbPassword;

    public Path createEncryptedBackup() {
        try {
            Path backupDir = Paths.get(backupDirectory);
            Files.createDirectories(backupDir);

            String stamp = Instant.now().toString().replace(":", "-");
            Path plain = backupDir.resolve("db-backup-" + stamp + ".sql");
            Path encrypted = backupDir.resolve("db-backup-" + stamp + ".sql.enc");

            runPgDump(plain);
            encrypt(plain, encrypted);
            Files.deleteIfExists(plain);

            return encrypted;
        } catch (Exception ex) {
            throw new IllegalStateException("Nightly backup failed", ex);
        }
    }

    private void runPgDump(Path output) throws IOException, InterruptedException {
        ProcessBuilder pb = new ProcessBuilder(
                "pg_dump",
                "-h", dbHost,
                "-p", dbPort,
                "-U", dbUser,
                "-d", dbName,
                "-f", output.toString()
        );
        pb.environment().put("PGPASSWORD", dbPassword);
        Process process = pb.start();
        int exit = process.waitFor();
        if (exit != 0) {
            throw new IllegalStateException("pg_dump exited with code " + exit);
        }
    }

    private void encrypt(Path input, Path output) throws Exception {
        byte[] plain = Files.readAllBytes(input);
        byte[] iv = new byte[IV_LENGTH];
        new SecureRandom().nextBytes(iv);

        SecretKey key = EncryptionKeyProvider.getKey();
        Cipher cipher = Cipher.getInstance("AES/GCM/NoPadding");
        cipher.init(Cipher.ENCRYPT_MODE, key, new GCMParameterSpec(TAG_BITS, iv));
        byte[] cipherText = cipher.doFinal(plain);

        byte[] payload = new byte[iv.length + cipherText.length];
        System.arraycopy(iv, 0, payload, 0, iv.length);
        System.arraycopy(cipherText, 0, payload, iv.length, cipherText.length);
        Files.write(output, payload);
    }
}
