@Component
public class ScheduledJobs {

    private final BackupService backupService;
    private final SafetyInspectionGenerationService safetyInspectionGenerationService;
    private final NotificationService notificationService;

    public ScheduledJobs(BackupService backupService,
                         SafetyInspectionGenerationService safetyInspectionGenerationService,
                         NotificationService notificationService) {
        this.backupService = backupService;
        this.safetyInspectionGenerationService = safetyInspectionGenerationService;
        this.notificationService = notificationService;
    }

    @Async
    @Scheduled(cron = "0 0 2 * * *")
    public void nightlyEncryptedBackup() {
        backupService.createEncryptedBackup();
    }

    @Async
    @Scheduled(cron = "0 15 1 * * *")
    public void generateCriticalAssetInspections() {
        safetyInspectionGenerationService.generateNext30DaysForCriticalAssets();
    }

    @Async
    @Scheduled(cron = "0 */5 * * * *")
    public void processNotificationBanners() {
        notificationService.queueTemplateBanners();
        notificationService.processPendingBanners();
    }
}
