package com.eagle.app.service;

import com.eagle.app.model.BannerStatus;
import com.eagle.app.model.NotificationBanner;
import com.eagle.app.model.Reservation;
import com.eagle.app.repository.NotificationBannerRepository;
import com.eagle.app.repository.ReservationRepository;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.List;

@Service
public class NotificationService {

    private final ReservationRepository reservationRepository;
    private final NotificationBannerRepository notificationBannerRepository;

    public NotificationService(ReservationRepository reservationRepository,
                               NotificationBannerRepository notificationBannerRepository) {
        this.reservationRepository = reservationRepository;
        this.notificationBannerRepository = notificationBannerRepository;
    }

    public int queueTemplateBanners() {
        Instant now = Instant.now();
        int created = 0;

        List<Reservation> arrivals = reservationRepository.findArrivalsBetween(now, now.plus(30, ChronoUnit.MINUTES));
        for (Reservation reservation : arrivals) {
            created += queueIfMissing(reservation, "ARRIVAL_30M",
                    "Reminder: your reservation starts in 30 minutes.", reservation.getStartTime().minus(30, ChronoUnit.MINUTES));
        }

        List<Reservation> checkouts = reservationRepository.findCheckoutsBetween(now, now.plus(10, ChronoUnit.MINUTES));
        for (Reservation reservation : checkouts) {
            created += queueIfMissing(reservation, "CHECKOUT_10M",
                    "Reminder: checkout is in 10 minutes.", reservation.getEndTime().minus(10, ChronoUnit.MINUTES));
        }

        return created;
    }

    public int processPendingBanners() {
        List<NotificationBanner> due = notificationBannerRepository
                .findByStatusAndScheduledForLessThanEqual(BannerStatus.PENDING, Instant.now());
        for (NotificationBanner banner : due) {
            banner.setStatus(BannerStatus.PROCESSED);
        }
        notificationBannerRepository.saveAll(due);
        return due.size();
    }

    private int queueIfMissing(Reservation reservation, String templateKey, String message, Instant scheduledFor) {
        if (notificationBannerRepository.existsByReservationIdAndTemplateKey(reservation.getId(), templateKey)) {
            return 0;
        }
        NotificationBanner banner = new NotificationBanner();
        banner.setReservation(reservation);
        banner.setTargetUser(reservation.getRequester());
        banner.setTemplateKey(templateKey);
        banner.setMessage(message);
        banner.setScheduledFor(scheduledFor);
        banner.setStatus(BannerStatus.PENDING);
        notificationBannerRepository.save(banner);
        return 1;
    }
}
