package com.eagle.app.service;

import com.eagle.app.model.PaymentIdempotencyKey;
import com.eagle.app.repository.PaymentIdempotencyKeyRepository;
import com.fasterxml.jackson.core.JsonProcessingException;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.nio.charset.StandardCharsets;
import java.security.MessageDigest;
import java.util.HexFormat;
import java.util.UUID;

@Service
public class OfflinePaymentService {

    private final PaymentIdempotencyKeyRepository idempotencyKeyRepository;
    private final ObjectMapper objectMapper;

    public OfflinePaymentService(PaymentIdempotencyKeyRepository idempotencyKeyRepository, ObjectMapper objectMapper) {
        this.idempotencyKeyRepository = idempotencyKeyRepository;
        this.objectMapper = objectMapper;
    }

    @Transactional
    public OfflinePaymentResponse processPayment(OfflinePaymentRequest request) {
        String requestChecksum = checksum(request);
        return idempotencyKeyRepository.findByClientGeneratedKey(request.clientGeneratedKey())
                .map(saved -> {
                    if (!saved.getRequestChecksum().equals(requestChecksum)) {
                        throw new IllegalArgumentException("Idempotency key reuse with different payload is not allowed");
                    }
                    return deserializeResponse(saved);
                })
                .orElseGet(() -> createAndStore(request));
    }

    private OfflinePaymentResponse createAndStore(OfflinePaymentRequest request) {
        OfflinePaymentResponse response = new OfflinePaymentResponse(
                "PAY-" + UUID.randomUUID(),
                request.orderId(),
                request.amount(),
                request.currency(),
                "PROCESSED"
        );

        PaymentIdempotencyKey key = new PaymentIdempotencyKey();
        key.setClientGeneratedKey(request.clientGeneratedKey());
        key.setRequestChecksum(checksum(request));
        key.setResponsePayload(serializeResponse(response));
        idempotencyKeyRepository.save(key);
        return response;
    }

    private OfflinePaymentResponse deserializeResponse(PaymentIdempotencyKey key) {
        try {
            return objectMapper.readValue(key.getResponsePayload(), OfflinePaymentResponse.class);
        } catch (JsonProcessingException e) {
            throw new IllegalStateException("Failed to deserialize cached payment response", e);
        }
    }

    private String serializeResponse(OfflinePaymentResponse response) {
        try {
            return objectMapper.writeValueAsString(response);
        } catch (JsonProcessingException e) {
            throw new IllegalStateException("Failed to serialize payment response", e);
        }
    }

    private String checksum(OfflinePaymentRequest request) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            String payload = request.orderId() + "|" + request.amount() + "|" + request.currency();
            return HexFormat.of().formatHex(digest.digest(payload.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new IllegalStateException("Unable to checksum payment request", e);
        }
    }
}

