package com.eagle.app.controller;

import com.eagle.app.dto.UserMaskedResponse;
import com.eagle.app.repository.UserRepository;
import com.eagle.app.util.MaskingUtil;
import com.eagle.app.util.PaginationHeaderUtil;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1/users")
public class UserController {

    private final UserRepository userRepository;

    public UserController(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @GetMapping
    public ResponseEntity<Page<UserMaskedResponse>> list(Pageable pageable) {
        Page<UserMaskedResponse> page = userRepository.findAll(pageable)
                .map(user -> new UserMaskedResponse(
                        user.getId(),
                        user.getUsername(),
                        user.getEmail(),
                        MaskingUtil.mask(user.getStaffContactInfo())
                ));
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }
}

