+import org.springframework.context.annotation.Configuration;
+import org.springframework.web.filter.OncePerRequestFilter;
+import org.springframework.web.filter.ShallowEtagHeaderFilter;
+
+import java.io.IOException;
+import java.util.concurrent.TimeUnit;
+
+@Configuration
+public class HttpCachingConfig {
+
+    @Bean
+    public FilterRegistrationBean<Filter> shallowEtagFilter() {
+        FilterRegistrationBean<Filter> registration = new FilterRegistrationBean<>();
+        registration.setFilter(new ShallowEtagHeaderFilter());
+        registration.addUrlPatterns("/api/v1/*", "/", "/index.html", "/app.js", "/styles.css");
+        registration.setOrder(1);
+        return registration;
+    }
+
+    @Bean
+    public FilterRegistrationBean<OncePerRequestFilter> cacheControlFilter() {
+        OncePerRequestFilter filter = new OncePerRequestFilter() {
+            @Override
+            protected void doFilterInternal(jakarta.servlet.http.HttpServletRequest request,
+                                            jakarta.servlet.http.HttpServletResponse response,
+                                            jakarta.servlet.FilterChain filterChain)
+                    throws jakarta.servlet.ServletException, IOException {
+                filterChain.doFilter(request, response);
+                if ("GET".equalsIgnoreCase(request.getMethod())) {
+                    String path = request.getRequestURI();
+                    if (path.startsWith("/api/v1/")) {
+                        response.setHeader("Cache-Control", "private, max-age=60, must-revalidate");
+                    } else {
+                        response.setHeader("Cache-Control", "public, max-age=" + TimeUnit.MINUTES.toSeconds(10));
+                    }
+                }
+            }
+        };
+
+        FilterRegistrationBean<OncePerRequestFilter> registration = new FilterRegistrationBean<>();
+        registration.setFilter(filter);
+        registration.addUrlPatterns("/api/v1/*", "/", "/index.html", "/app.js", "/styles.css");
+        registration.setOrder(2);
+        return registration;
+    }
+}
