package com.eagle.app.service;

import com.eagle.app.model.Asset;
import com.eagle.app.model.AssetLifecycleState;
import com.eagle.app.model.AssetType;
import com.eagle.app.model.Inspection;
import com.eagle.app.model.RoleName;
import com.eagle.app.model.User;
import com.eagle.app.repository.AssetRepository;
import com.eagle.app.repository.InspectionRepository;
import com.eagle.app.repository.UserRepository;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.List;
import java.util.Set;

@Service
public class SafetyInspectionGenerationService {

    private final AssetRepository assetRepository;
    private final InspectionRepository inspectionRepository;
    private final UserRepository userRepository;

    public SafetyInspectionGenerationService(AssetRepository assetRepository,
                                             InspectionRepository inspectionRepository,
                                             UserRepository userRepository) {
        this.assetRepository = assetRepository;
        this.inspectionRepository = inspectionRepository;
        this.userRepository = userRepository;
    }

    public int generateNext30DaysForCriticalAssets() {
        User inspector = userRepository.findFirstByRolesName(RoleName.TECH)
                .or(() -> userRepository.findFirstByRolesName(RoleName.ADMIN))
                .orElse(null);
        if (inspector == null) {
            return 0;
        }

        List<Asset> criticalAssets = assetRepository.findByAssetTypeInAndLifecycleStateNot(
                Set.of(AssetType.PROJECTOR, AssetType.HVAC),
                AssetLifecycleState.RETIRED
        );

        int created = 0;
        Instant now = Instant.now();
        Instant in30Days = now.plus(30, ChronoUnit.DAYS);

        for (Asset asset : criticalAssets) {
            Long roomId = asset.getRoom().getId();
            boolean exists = inspectionRepository.existsByRoomIdAndInspectionTimeBetween(roomId, now, in30Days);
            if (exists) {
                continue;
            }
            Inspection inspection = new Inspection();
            inspection.setRoom(asset.getRoom());
            inspection.setInspector(inspector);
            inspection.setInspectionTime(in30Days);
            inspection.setOutcome("SCHEDULED");
            inspection.setNotes("Auto-generated 30-day safety inspection for critical asset " + asset.getTag());
            inspectionRepository.save(inspection);
            created++;
        }

        return created;
    }
}

