@RestController
@RequestMapping("/api/v1/operations")
public class OperationsController {

    private final PromotionRepository promotionRepository;
    private final AnnouncementRepository announcementRepository;
    private final AttachmentModerationItemRepository moderationRepository;
    private final UserRepository userRepository;

    public OperationsController(PromotionRepository promotionRepository,
                                AnnouncementRepository announcementRepository,
                                AttachmentModerationItemRepository moderationRepository,
                                UserRepository userRepository) {
        this.promotionRepository = promotionRepository;
        this.announcementRepository = announcementRepository;
        this.moderationRepository = moderationRepository;
        this.userRepository = userRepository;
    }

    @GetMapping("/promotions")
    public ResponseEntity<Page<Promotion>> promotions(Pageable pageable) {
        Page<Promotion> page = promotionRepository.findAll(pageable);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @PostMapping("/promotions")
    public Promotion savePromotion(@RequestBody Promotion promotion) {
        return promotionRepository.save(promotion);
    }

    @PostMapping("/announcements")
    public Announcement saveAnnouncement(@RequestBody AnnouncementRequest request) {
        Announcement announcement = new Announcement();
        announcement.setTitle(request.title());
        announcement.setMessage(request.message());
        announcement.setPublished(request.published());
        return announcementRepository.save(announcement);
    }

    @GetMapping("/announcements")
    public ResponseEntity<Page<Announcement>> announcements(Pageable pageable) {
        Page<Announcement> page = announcementRepository.findAll(pageable);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @PostMapping("/moderation-queue")
    public ModerationItemResponse saveModerationItem(@RequestBody ModerationRequest request) {
        AttachmentModerationItem item = new AttachmentModerationItem();
        item.setFileName(request.fileName());
        item.setContentType(request.contentType());
        item.setStatus(request.status());
        item.setReason(request.reason());
        if (request.uploadedById() != null) {
            item.setUploadedBy(userRepository.findById(request.uploadedById()).orElseThrow(() -> new IllegalArgumentException("uploadedBy not found")));
        }
        return ModerationItemResponse.from(moderationRepository.save(item));
    }

    @GetMapping("/moderation-queue")
    public ResponseEntity<Page<ModerationItemResponse>> moderationQueue(Pageable pageable) {
        Page<ModerationItemResponse> page = moderationRepository.findAll(pageable).map(ModerationItemResponse::from);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }
}

