+const state = {
+    token: localStorage.getItem("eagle_token"),
+    username: localStorage.getItem("eagle_username"),
+    activePanel: "requester",
+    loadedPanels: new Set()
+};
+
+if (document.getElementById("login-form")) {
+    initializeLoginPage();
+}
+
+if (document.querySelector(".dashboard-shell")) {
+    initializeDashboard();
+}
+
+function initializeLoginPage() {
+    if (state.token) {
+        window.location.replace("/dashboard.html");
+        return;
+    }
+
+    document.getElementById("login-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        const username = document.getElementById("username").value;
+        const password = document.getElementById("password").value;
+        const status = document.getElementById("session-status");
+        status.textContent = "Authenticating...";
+
+        try {
+            const payload = await fetchJson("/api/v1/auth/login", "POST", { username, password });
+            localStorage.setItem("eagle_token", payload.token);
+            localStorage.setItem("eagle_username", username);
+            window.location.replace("/dashboard.html");
+        } catch (error) {
+            status.textContent = "Authentication failed. Check your credentials and try again.";
+        }
+    });
+}
+
+function initializeDashboard() {
+    if (!state.token) {
+        window.location.replace("/login.html");
+        return;
+    }
+
+    document.getElementById("active-user").textContent = state.username || "workspace user";
+    document.getElementById("logout-btn").addEventListener("click", logout);
+
+    document.querySelectorAll(".nav-btn").forEach((button) => {
+        button.addEventListener("click", async () => {
+            await activatePanel(button.dataset.panel);
+        });
+    });
+
+    wireForms();
+    activatePanel("requester");
+}
+
+function wireForms() {
+    document.getElementById("banner-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        await api("/api/v1/frontdesk/banner-templates", "POST", {
+            templateKey: document.getElementById("banner-key").value,
+            minutesBefore: Number(document.getElementById("banner-minutes").value),
+            message: document.getElementById("banner-message").value,
+            active: true
+        });
+        await loadFrontDesk(true);
+    });
+
+    document.getElementById("handoff-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        await api("/api/v1/frontdesk/shift-handoffs", "POST", {
+            fromUserId: Number(document.getElementById("handoff-from").value),
+            toUserId: Number(document.getElementById("handoff-to").value),
+            handoffTime: new Date().toISOString(),
+            summary: document.getElementById("handoff-summary").value,
+            pendingTasks: document.getElementById("handoff-tasks").value
+        });
+        await loadFrontDesk(true);
+    });
+
+    document.getElementById("asset-status-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        await api(`/api/v1/assets/${document.getElementById("asset-id").value}/status`, "PATCH", {
+            status: document.getElementById("asset-operational-status").value,
+            lifecycleState: document.getElementById("asset-lifecycle-state").value
+        });
+        await Promise.all([loadMaintenance(true), loadRequester(true)]);
+    });
+
+    document.getElementById("promotion-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        await api("/api/v1/operations/promotions", "POST", {
+            code: document.getElementById("promotion-code").value,
+            percentage: Number(document.getElementById("promotion-percent").value),
+            promotionType: document.getElementById("promotion-type").value,
+            startsAt: new Date(Date.now() - 86400000).toISOString(),
+            endsAt: new Date(Date.now() + 86400000 * 30).toISOString(),
+            active: true
+        });
+        await loadOperations(true);
+    });
+
+    document.getElementById("announcement-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        await api("/api/v1/operations/announcements", "POST", {
+            title: document.getElementById("announcement-title").value,
+            message: document.getElementById("announcement-message").value,
+            published: true
+        });
+        await loadOperations(true);
+    });
+
+    document.getElementById("scorecard-form").addEventListener("submit", async (event) => {
+        event.preventDefault();
+        const from = document.getElementById("effective-from").value;
+        const to = document.getElementById("effective-to").value;
+        const definitionText = document.getElementById("scorecard-definition").value;
+        const feedback = document.getElementById("scorecard-feedback");
+
+        if (!/^\d{2}\/\d{2}\/\d{4}$/.test(from) || (to && !/^\d{2}\/\d{2}\/\d{4}$/.test(to))) {
+            feedback.textContent = "Dates must use MM/DD/YYYY.";
+            return;
+        }
+
+        const weighted = JSON.parse(definitionText);
+        const weightSum = Object.values(weighted).reduce((sum, value) => sum + Number(value), 0);
+        if (weightSum !== 100) {
+            feedback.textContent = "Weights must sum to 100.";
+            return;
+        }
+
+        await api("/api/v1/metrics/scorecards", "POST", {
+            metricKey: document.getElementById("metric-key").value,
+            effectiveFrom: from,
+            effectiveTo: to,
+            weightedDimensions: weighted,
+            definition: definitionText
+        });
+        feedback.textContent = "Scorecard saved successfully.";
+        await loadAdmin(true);
+    });
+}
+
+async function activatePanel(panelId) {
+    document.querySelectorAll(".nav-btn").forEach((item) => item.classList.toggle("active", item.dataset.panel === panelId));
+    document.querySelectorAll(".panel").forEach((panel) => panel.classList.toggle("active", panel.id === panelId));
+    state.activePanel = panelId;
+    document.getElementById("panel-title").textContent = titleForPanel(panelId);
+    await loadPanel(panelId, !state.loadedPanels.has(panelId));
+    state.loadedPanels.add(panelId);
+}
+
+async function loadPanel(panelId, firstLoad) {
+    setStatus(firstLoad ? "Loading workspace data..." : "Refreshing workspace...");
+    const loaders = {
+        requester: loadRequester,
+        frontdesk: loadFrontDesk,
+        maintenance: loadMaintenance,
+        operations: loadOperations,
+        admin: loadAdmin
+    };
+    try {
+        await loaders[panelId](firstLoad);
+        setStatus("Workspace is up to date.");
+    } catch (error) {
+        setStatus("Workspace load failed.");
+    }
+}
+
+async function loadRequester(force) {
+    const rooms = await api("/api/v1/catalog/rooms?page=0&size=20");
+    render("rooms-grid", rooms.content.map((room) =>
+        `<article class="workspace-card">
+            <div class="item-meta">${room.location}</div>
+            <h3>${room.roomNumber}</h3>
+            <p>Capacity ${room.capacity} • ${room.roomType}</p>
+            <p class="${room.reservable ? "workspace-subcopy" : "warning"}">${room.warning || "Reservable and ready to book."}</p>
+        </article>`
+    ));
+}
+
+async function loadFrontDesk(force) {
+    const [schedule, banners, handoffs] = await Promise.all([
+        api("/api/v1/frontdesk/schedule-board?page=0&size=20"),
+        api("/api/v1/frontdesk/banner-templates?page=0&size=20"),
+        api("/api/v1/frontdesk/shift-handoffs?page=0&size=20")
+    ]);
+
+    render("schedule-board", schedule.content.map((item) =>
+        `<div class="item"><strong>Room ${item.roomId}</strong><div>${formatDateTime(item.startTime)} - ${formatDateTime(item.endTime)}</div><div class="item-meta">${item.status}</div></div>`
+    ));
+    render("banner-list", banners.content.map((item) =>
+        `<div class="item"><strong>${item.templateKey}</strong><div>${item.minutesBefore} minutes before event</div><div class="item-meta">${item.message}</div></div>`
+    ));
+    render("handoff-list", handoffs.content.map((item) =>
+        `<div class="item"><strong>${item.fromUser} to ${item.toUser}</strong><div>${item.summary}</div><div class="item-meta">${item.pendingTasks || "No pending tasks"}</div></div>`
+    ));
+}
+
+async function loadMaintenance(force) {
+    const [inspections, tickets, assets] = await Promise.all([
+        api("/api/v1/maintenance/inspections?page=0&size=20"),
+        api("/api/v1/maintenance/tickets?page=0&size=20"),
+        api("/api/v1/assets?page=0&size=20")
+    ]);
+
+    render("inspection-list", inspections.content.map((item) =>
+        `<div class="item"><strong>${item.roomNumber}</strong><div>${formatDate(item.inspectionTime)}</div><div class="item-meta">${item.outcome}</div></div>`
+    ));
+    render("ticket-list", tickets.content.map((item) =>
+        `<div class="item"><strong>${item.title}</strong><div>SLA breached: ${item.slaBreached ? "Yes" : "No"}</div><div class="item-meta">Parts ${item.partsCost || 0} • Labor ${item.laborHours || 0}</div></div>`
+    ));
+    render("asset-list", assets.content.map((item) =>
+        `<div class="item"><strong>${item.name}</strong><div>${item.assetType}</div><div class="${item.lifecycleState === "UNDER_REPAIR" ? "warning" : "item-meta"}">${item.operationalStatus} • ${item.lifecycleState}</div></div>`
+    ));
+}
+
+async function loadOperations(force) {
+    const [promotions, announcements, moderation] = await Promise.all([
+        api("/api/v1/operations/promotions?page=0&size=20"),
+        api("/api/v1/operations/announcements?page=0&size=20"),
+        api("/api/v1/operations/moderation-queue?page=0&size=20")
+    ]);
+
+    render("promotion-list", promotions.content.map((item) =>
+        `<div class="item"><strong>${item.code}</strong><div>${item.promotionType}</div><div class="item-meta">${item.percentage}% active discount</div></div>`
+    ));
+    render("announcement-list", announcements.content.map((item) =>
+        `<div class="item"><strong>${item.title}</strong><div>${item.message}</div></div>`
+    ));
+    render("moderation-list", moderation.content.map((item) =>
+        `<div class="item"><strong>${item.fileName}</strong><div>${item.status}</div><div class="item-meta">${item.reason || "Awaiting review notes"}</div></div>`
+    ));
+}
+
+async function loadAdmin(force) {
+    const scorecards = await api("/api/v1/metrics/scorecards?page=0&size=20");
+    render("scorecard-list", scorecards.content.map((item) =>
+        `<div class="item"><strong>${item.metricKey} v${item.version}</strong><div>${item.effectiveFrom}</div><div class="item-meta">${item.definition}</div></div>`
+    ));
+}
+
+async function api(url, method = "GET", body) {
+    const headers = { "Content-Type": "application/json" };
+    if (state.token) {
+        headers.Authorization = `Bearer ${state.token}`;
+    }
+    return fetchJson(url, method, body, headers);
+}
+
+async function fetchJson(url, method, body, headers = { "Content-Type": "application/json" }) {
+    const response = await fetch(url, {
+        method,
+        headers,
+        body: body ? JSON.stringify(body) : undefined
+    });
+
+    if (response.status === 401) {
+        logout();
+        throw new Error("Unauthorized");
+    }
+
+    if (!response.ok) {
+        const text = await response.text();
+        throw new Error(text || `Request failed: ${response.status}`);
+    }
+
+    return response.status === 204 ? {} : response.json();
+}
+
+function render(id, chunks) {
+    document.getElementById(id).innerHTML = chunks.join("") || "<div class=\"item\">No records yet.</div>";
+}
+
+function titleForPanel(panelId) {
+    return {
+        requester: "Requester Workspace",
+        frontdesk: "Front Desk Workspace",
+        maintenance: "Maintenance Workspace",
+        operations: "Operations Workspace",
+        admin: "Administrator Workspace"
+    }[panelId];
+}
+
+function setStatus(message) {
+    const target = document.getElementById("load-status");
+    if (target) {
+        target.textContent = message;
+    }
+}
+
+function logout() {
+    localStorage.removeItem("eagle_token");
+    localStorage.removeItem("eagle_username");
+    window.location.replace("/login.html");
+}
+
+function formatDateTime(value) {
+    return new Date(value).toLocaleString();
+}
+
+function formatDate(value) {
+    return new Date(value).toLocaleDateString();
+}
*** End Patch
"}

