package com.eagle.app.service;

import com.eagle.app.exception.BusinessRuleViolationException;
import com.eagle.app.model.MetricTemplate;
import com.eagle.app.repository.MetricTemplateRepository;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.time.format.ResolverStyle;

@Service
public class MetricLibraryService {

    private static final DateTimeFormatter US_DATE =
            DateTimeFormatter.ofPattern("MM/dd/uuuu").withResolverStyle(ResolverStyle.STRICT);

    private final MetricTemplateRepository metricTemplateRepository;

    public MetricLibraryService(MetricTemplateRepository metricTemplateRepository) {
        this.metricTemplateRepository = metricTemplateRepository;
    }

    @Transactional
    public MetricTemplate createVersionedScorecard(ScorecardRequest request) {
        int weightSum = request.weightedDimensions().values().stream().mapToInt(Integer::intValue).sum();
        if (weightSum != 100) {
            throw new BusinessRuleViolationException("Scorecard weights must sum to 100");
        }

        String effectiveFromValue = request.effectiveFrom() == null ? null : request.effectiveFrom().trim();
        String effectiveToValue = request.effectiveTo() == null ? null : request.effectiveTo().trim();
        if (effectiveFromValue == null || effectiveFromValue.isBlank()) {
            throw new BusinessRuleViolationException("effectiveFrom is required");
        }

        LocalDate effectiveFrom = LocalDate.parse(effectiveFromValue, US_DATE);
        LocalDate effectiveTo = effectiveToValue == null || effectiveToValue.isBlank()
                ? null
                : LocalDate.parse(effectiveToValue, US_DATE);

        if (effectiveTo != null && effectiveTo.isBefore(effectiveFrom)) {
            throw new BusinessRuleViolationException("effectiveTo must be on or after effectiveFrom");
        }

        MetricTemplate metricTemplate = new MetricTemplate();
        metricTemplate.setMetricKey(request.metricKey());
        metricTemplate.setVersion(nextVersion(request.metricKey()));
        metricTemplate.setDefinition(request.definition());
        metricTemplate.setEffectiveFrom(effectiveFrom);
        metricTemplate.setEffectiveTo(effectiveTo);
        metricTemplate.setActive(true);

        return metricTemplateRepository.save(metricTemplate);
    }

    public void validateWeightSum(ScorecardRequest request) {
        int weightSum = request.weightedDimensions().values().stream().mapToInt(Integer::intValue).sum();
        if (weightSum != 100) {
            throw new BusinessRuleViolationException("Scorecard weights must sum to 100");
        }
    }

    private int nextVersion(String metricKey) {
        return metricTemplateRepository.findAll().stream()
                .filter(template -> template.getMetricKey().equals(metricKey))
                .map(MetricTemplate::getVersion)
                .max(Integer::compareTo)
                .orElse(0) + 1;
    }
}

