package com.eagle.app.service;

import com.eagle.app.model.Room;
import com.eagle.app.repository.RoomRepository;
import org.springframework.stereotype.Service;

import java.util.List;

@Service
public class WarningAlternativeService {

    private final RoomRepository roomRepository;

    public WarningAlternativeService(RoomRepository roomRepository) {
        this.roomRepository = roomRepository;
    }

    public String buildWarningAndAlternatives(Room impactedRoom) {
        List<Room> alternatives = roomRepository.findByLocation_IdAndRoomType_IdAndReservableTrueAndIdNot(
                impactedRoom.getLocation().getId(),
                impactedRoom.getRoomType().getId(),
                impactedRoom.getId()
        );

        if (alternatives.isEmpty()) {
            return "Essential asset is out of service. Room marked non-reservable. No alternatives found.";
        }

        String roomNumbers = alternatives.stream().map(Room::getNumber).reduce((a, b) -> a + ", " + b).orElse("none");
        return "Essential asset is out of service. Room marked non-reservable. Alternatives: " + roomNumbers;
    }
}

