import java.time.Instant;

@Configuration
public class DataBootstrapConfig {

    @Bean
    CommandLineRunner bootstrapRoles(RoleRepository roleRepository,
                                     UserRepository userRepository,
                                     PasswordEncoder passwordEncoder,
                                     LocationRepository locationRepository,
                                     RoomTypeRepository roomTypeRepository,
                                     RoomRepository roomRepository,
                                     AssetRepository assetRepository,
                                     MaintenanceTicketRepository maintenanceTicketRepository,
                                     PromotionRepository promotionRepository) {
        return args -> {
            Arrays.stream(RoleName.values()).forEach(roleName ->
                roleRepository.findByName(roleName).orElseGet(() -> {
                    Role role = new Role();
                    role.setName(roleName);
                    return roleRepository.save(role);
                })
            );

            Map<RoleName, String> users = Map.of(
                    RoleName.REQUESTER, "requester.demo",
                    RoleName.AGENT, "agent.demo",
                    RoleName.TECH, "tech.demo",
                    RoleName.OPS, "ops.demo",
                    RoleName.ADMIN, "admin.demo"
            );

            for (Map.Entry<RoleName, String> entry : users.entrySet()) {
                if (userRepository.findByUsername(entry.getValue()).isPresent()) {
                    continue;
                }
                Role role = roleRepository.findByName(entry.getKey())
                        .orElseThrow(() -> new IllegalStateException("Missing role " + entry.getKey()));

                User user = new User();
                user.setUsername(entry.getValue());
                user.setEmail(entry.getValue() + "@eagle.local");
                user.setPasswordHash(passwordEncoder.encode("ChangeMe!1234"));
                user.setStaffContactInfo("+1-555-0100");
                user.setRoles(Set.of(role));
                userRepository.save(user);
            }

            Location hq = locationRepository.findByCode("HQ").orElseGet(() -> {
                Location location = new Location();
                location.setCode("HQ");
                location.setName("Main Campus");
                location.setAddress("100 Enterprise Way");
                return locationRepository.save(location);
            });

            RoomType boardroom = roomTypeRepository.findByName("Boardroom").orElseGet(() -> {
                RoomType roomType = new RoomType();
                roomType.setName("Boardroom");
                roomType.setDescription("Executive meeting room");
                return roomTypeRepository.save(roomType);
            });

            Room roomA = roomRepository.findAll().stream().filter(r -> "A101".equals(r.getNumber())).findFirst().orElseGet(() -> {
                Room room = new Room();
                room.setLocation(hq);
                room.setRoomType(boardroom);
                room.setNumber("A101");
                room.setFloorNumber(1);
                room.setCapacity(14);
                return roomRepository.save(room);
            });

            Room roomB = roomRepository.findAll().stream().filter(r -> "A102".equals(r.getNumber())).findFirst().orElseGet(() -> {
                Room room = new Room();
                room.setLocation(hq);
                room.setRoomType(boardroom);
                room.setNumber("A102");
                room.setFloorNumber(1);
                room.setCapacity(12);
                return roomRepository.save(room);
            });

            if (assetRepository.findAll().isEmpty()) {
                Asset projector = new Asset();
                projector.setRoom(roomA);
                projector.setTag("PROJ-A101");
                projector.setName("Projector A101");
                projector.setAssetType(AssetType.PROJECTOR);
                assetRepository.save(projector);

                Asset hvac = new Asset();
                hvac.setRoom(roomA);
                hvac.setTag("HVAC-A101");
                hvac.setName("HVAC A101");
                hvac.setAssetType(AssetType.HVAC);
                assetRepository.save(hvac);
            }

            if (promotionRepository.findAll().isEmpty()) {
                Promotion promotion = new Promotion();
                promotion.setCode("EARLY10");
                promotion.setPercentage(BigDecimal.TEN);
                promotion.setPromotionType(PromotionType.EARLY_BIRD);
                promotion.setStartsAt(Instant.now().minusSeconds(86400));
                promotion.setEndsAt(Instant.now().plusSeconds(86400 * 30));
                promotion.setActive(true);
                promotionRepository.save(promotion);
            }

            if (maintenanceTicketRepository.findAll().isEmpty() && !assetRepository.findAll().isEmpty()) {
                MaintenanceTicket ticket = new MaintenanceTicket();
                ticket.setAsset(assetRepository.findAll().getFirst());
                ticket.setReportedBy(userRepository.findByUsername("agent.demo").orElseThrow());
                ticket.setAssignedTo(userRepository.findByUsername("tech.demo").orElseThrow());
                ticket.setTitle("Projector lamp replacement");
                ticket.setDescription("Projector bulb nearing end of life");
                ticket.setStatus(TicketStatus.OPEN);
                ticket.setSeverity(Severity.MEDIUM);
                maintenanceTicketRepository.save(ticket);
            }
        };
    }
}

