package com.eagle.app.service;

import com.eagle.app.model.Promotion;
import com.eagle.app.model.PromotionType;
import com.eagle.app.repository.PromotionRepository;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Instant;

@Service
public class PromotionService {

    private final PromotionRepository promotionRepository;

    public PromotionService(PromotionRepository promotionRepository) {
        this.promotionRepository = promotionRepository;
    }

    public BigDecimal applyDiscount(String promoCode, BigDecimal orderAmount, Instant orderTime) {
        Promotion promotion = promotionRepository.findByCode(promoCode)
                .orElseThrow(() -> new IllegalArgumentException("Invalid promo code"));

        if (!promotion.isActive() || orderTime.isBefore(promotion.getStartsAt()) || orderTime.isAfter(promotion.getEndsAt())) {
            throw new IllegalArgumentException("Promotion is not active for this order time");
        }

        BigDecimal discountPercent = switch (promotion.getPromotionType()) {
            case EARLY_BIRD -> promotion.getPercentage();
            case TIERED -> resolveTieredPercent(promotion, orderAmount);
        };

        BigDecimal multiplier = BigDecimal.ONE.subtract(discountPercent.divide(BigDecimal.valueOf(100), 6, RoundingMode.HALF_UP));
        return orderAmount.multiply(multiplier).setScale(2, RoundingMode.HALF_UP);
    }

    private BigDecimal resolveTieredPercent(Promotion promotion, BigDecimal amount) {
        if (promotion.getTierThresholdAmount() == null || promotion.getTierPercentage() == null) {
            return promotion.getPercentage();
        }
        if (amount.compareTo(promotion.getTierThresholdAmount()) >= 0) {
            return promotion.getTierPercentage();
        }
        return promotion.getPercentage();
    }
}

