async function loadRequester(firstLoad) {
    if (firstLoad) {
        await loadRequesterFilterOptions();
    }

    syncReservationTimesFromFilters();

    const startValue = document.getElementById("filter-start").value;
    const endValue = document.getElementById("filter-end").value;
    const params = new URLSearchParams({ page: "0", size: "20" });

    const location = document.getElementById("filter-location").value;
    const roomType = document.getElementById("filter-room-type").value;
    const capacity = document.getElementById("filter-capacity").value;

    if (location) params.set("location", location);
    if (roomType) params.set("roomType", roomType);
    if (capacity) params.set("minCapacity", capacity);
    if (startValue && endValue) {
        params.set("startTime", toIsoFromLocal(startValue));
        params.set("endTime", toIsoFromLocal(endValue));
    }

    const [rooms, reservations] = await Promise.all([
        api(`/api/v1/catalog/rooms?${params.toString()}`),
        api("/api/v1/reservations/mine?page=0&size=20")
    ]);

    state.roomsById = new Map(rooms.content.map((room) => [room.id, room]));
    render("rooms-grid", rooms.content.map(renderRoomCard));
    render("reservation-list", reservations.content.map(renderReservationItem));

    const feedback = document.getElementById("requester-feedback");
    if (rooms.content.length === 0) {
        feedback.textContent = "No rooms match the current filters. Try broadening the search window or capacity.";
    } else if (startValue && endValue) {
        feedback.textContent = "Availability is minute-accurate for the selected time range.";
    } else {
        feedback.textContent = "Choose a date and time range to check live availability and conflicts.";
    }

    refreshBookingEstimate();
}

