            prependItem("announcement-list", `<div class="item"><strong>${saved.title}</strong><div>${saved.message}</div></div>`);
            setStatus("Announcement published.");
        } catch (error) {
            setStatus(error.message);
        }
    });

    const userForm = document.getElementById("user-form");
    if (userForm) {
        userForm.addEventListener("submit", async (event) => {
            event.preventDefault();
            const feedback = document.getElementById("user-feedback");
            feedback.textContent = "";

            try {
                const saved = await api("/api/v1/users", "POST", {
                    username: document.getElementById("user-username").value,
                    email: document.getElementById("user-email").value,
                    password: document.getElementById("user-password").value,
                    role: document.getElementById("user-role").value,
                    staffContactInfo: document.getElementById("user-contact").value
                });
                prependItem("user-list", `<div class="item"><strong>${saved.username}</strong><div>${saved.email}</div><div class="item-meta">Contact ${saved.contactInfo}</div></div>`);
                feedback.textContent = "User created successfully.";
                setStatus("User created.");
                event.target.reset();
            } catch (error) {
                feedback.textContent = error.message;
            }
        });
    }

    document.getElementById("scorecard-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        const from = toUsDateString(document.getElementById("effective-from").value);
        const toInput = document.getElementById("effective-to").value;
        const to = toInput ? toUsDateString(toInput) : "";
        const feedback = document.getElementById("scorecard-feedback");
        const weighted = {
            quality: Number(document.getElementById("weight-quality").value),
            speed: Number(document.getElementById("weight-speed").value),
            compliance: Number(document.getElementById("weight-compliance").value),
            experience: Number(document.getElementById("weight-experience").value)
        };
        const definitionText = JSON.stringify(weighted);

        if (!from || (toInput && !to)) {
            feedback.textContent = "Please choose valid dates from the calendar.";
            return;
        }

        const weightSum = Object.values(weighted).reduce((sum, value) => sum + Number(value), 0);
        if (weightSum !== 100) {
            feedback.textContent = "Weights must sum to 100.";
            return;
        }

        const payload = {
            metricKey: document.getElementById("metric-key").value,
            effectiveFrom: from,
            weightedDimensions: weighted,
            definition: definitionText
        };
        if (to) {
            payload.effectiveTo = to;
        }

        try {
            const saved = await api("/api/v1/metrics/scorecards", "POST", payload);
            feedback.textContent = "Scorecard saved successfully.";
            prependItem("scorecard-list", `<div class="item"><strong>${saved.metricKey} v${saved.version}</strong><div>${saved.effectiveFrom}</div><div class="item-meta">${saved.definition}</div></div>`);
            setStatus("Scorecard saved.");
        } catch (error) {
            feedback.textContent = error.message;
        }
    });
}

function wireDelegatedActions() {
    document.addEventListener("click", async (event) => {
        const roomButton = event.target.closest("[data-room-select]");
        if (roomButton) {
            selectRoom(Number(roomButton.dataset.roomSelect));
            return;
        }

        const assetButton = event.target.closest("[data-asset-action]");
        if (assetButton) {
            try {
                await updateAssetState(
                    Number(assetButton.dataset.assetId),
                    assetButton.dataset.operationalStatus,
                    assetButton.dataset.lifecycleState
                );
            } catch (error) {
                setStatus(error.message);
            }
        }
    });
}

async function activatePanel(panelId) {
    if (!allowedPanels().includes(panelId)) {
        return;
    }
    document.querySelectorAll(".nav-btn").forEach((item) => item.classList.toggle("active", item.dataset.panel === panelId));
    document.querySelectorAll(".panel").forEach((panel) => panel.classList.toggle("active", panel.id === panelId));
    state.activePanel = panelId;
    document.getElementById("panel-title").textContent = titleForPanel(panelId);
    await loadPanel(panelId, !state.loadedPanels.has(panelId));
    state.loadedPanels.add(panelId);
}

async function loadPanel(panelId, firstLoad) {
    setStatus(firstLoad ? "Loading workspace data..." : "Refreshing workspace...");
    const loaders = {
        requester: loadRequester,
        frontdesk: loadFrontDesk,
        maintenance: loadMaintenance,
        operations: loadOperations,
        admin: loadAdmin
    };
    try {
        await loaders[panelId](firstLoad);
        setStatus("Workspace is up to date.");
    } catch (error) {
        setStatus(error.message || "Workspace load failed.");
    }
}

async function loadRequester(firstLoad) {
    if (firstLoad) {
        await loadRequesterFilterOptions();
    }

    syncReservationTimesFromFilters();

    const startValue = document.getElementById("filter-start").value;
    const endValue = document.getElementById("filter-end").value;
    const params = new URLSearchParams({ page: "0", size: "20" });

    const location = document.getElementById("filter-location").value;
    const roomType = document.getElementById("filter-room-type").value;
    const capacity = document.getElementById("filter-capacity").value;

    if (location) params.set("location", location);
    if (roomType) params.set("roomType", roomType);
    if (capacity) params.set("minCapacity", capacity);
    if (startValue && endValue) {
        params.set("startTime", toIsoFromLocal(startValue));
        params.set("endTime", toIsoFromLocal(endValue));
    }

    const [rooms, reservations] = await Promise.all([
        api(`/api/v1/catalog/rooms?${params.toString()}`),
        api("/api/v1/reservations/mine?page=0&size=20")
    ]);

    state.roomsById = new Map(rooms.content.map((room) => [room.id, room]));
    render("rooms-grid", rooms.content.map(renderRoomCard));
    render("reservation-list", reservations.content.map(renderReservationItem));

    const feedback = document.getElementById("requester-feedback");
    if (rooms.content.length === 0) {
        feedback.textContent = "No rooms match the current filters. Try broadening the search window or capacity.";
    } else if (startValue && endValue) {
        feedback.textContent = "Availability is minute-accurate for the selected time range.";
    } else {
        feedback.textContent = "Choose a date and time range to check live availability and conflicts.";
    }

    refreshBookingEstimate();
}

async function loadRequesterFilterOptions() {
    const [locations, roomTypes] = await Promise.all([
        api("/api/v1/catalog/locations"),
        api("/api/v1/catalog/room-types")
    ]);
    populateSelect("filter-location", ["", ...locations], "All locations");
    populateSelect("filter-room-type", ["", ...roomTypes], "All room types");
}

async function loadFrontDesk() {
    const [schedule, banners, handoffs] = await Promise.all([
        api("/api/v1/frontdesk/schedule-board?page=0&size=20"),
        api("/api/v1/frontdesk/banner-templates?page=0&size=20"),
        api("/api/v1/frontdesk/shift-handoffs?page=0&size=20")
    ]);

    render("schedule-board", schedule.content.map((item) =>
        `<div class="item"><strong>Room ${item.roomId}</strong><div>${formatDateTime(item.startTime)} - ${formatDateTime(item.endTime)}</div><div class="item-meta">${item.status}</div></div>`
    ));
    render("banner-list", banners.content.map((item) =>
        `<div class="item"><strong>${item.templateKey}</strong><div>${item.minutesBefore} minutes before event</div><div class="item-meta">${item.message}</div></div>`
    ));
    render("handoff-list", handoffs.content.map((item) =>
        `<div class="item"><strong>${item.fromUser} to ${item.toUser}</strong><div>${item.summary}</div><div class="item-meta">${item.pendingTasks || "No pending tasks"}</div></div>`
    ));
}

async function loadMaintenance() {
    const [inspections, tickets, assets] = await Promise.all([
        api("/api/v1/maintenance/inspections?page=0&size=20"),
        api("/api/v1/maintenance/tickets?page=0&size=20"),
        api("/api/v1/assets?page=0&size=50")
    ]);

    state.assetsById = new Map(assets.content.map((item) => [item.id, item]));

    render("inspection-list", inspections.content.map((item) =>
        `<div class="item"><strong>${item.roomNumber}</strong><div>${formatDate(item.inspectionTime)}</div><div class="item-meta">${item.outcome}</div></div>`
    ));
    render("ticket-list", tickets.content.map((item) =>
        `<div class="item"><strong>${item.title}</strong><div>SLA breached: ${item.slaBreached ? "Yes" : "No"}</div><div class="item-meta">Parts ${item.partsCost || 0} | Labor ${item.laborHours || 0}</div></div>`
    ));
    populateAssetSelect(assets.content);
    render("asset-list", assets.content.map(renderAssetCard));
}

async function loadOperations() {
    const [promotions, announcements, moderation] = await Promise.all([
        api("/api/v1/operations/promotions?page=0&size=20"),
        api("/api/v1/operations/announcements?page=0&size=20"),
        api("/api/v1/operations/moderation-queue?page=0&size=20")
    ]);

    render("promotion-list", promotions.content.map((item) =>
        `<div class="item"><strong>${item.code}</strong><div>${item.promotionType}</div><div class="item-meta">${item.percentage}% active discount</div></div>`
    ));
    render("announcement-list", announcements.content.map((item) =>
        `<div class="item"><strong>${item.title}</strong><div>${item.message}</div></div>`
    ));
    render("moderation-list", moderation.content.map((item) =>
        `<div class="item"><strong>${item.fileName}</strong><div>${item.status}</div><div class="item-meta">${item.reason || "Awaiting review notes"}</div></div>`
    ));
}

async function loadAdmin() {
    const [scorecards, users, assets] = await Promise.all([
        api("/api/v1/metrics/scorecards?page=0&size=20"),
        api("/api/v1/users?page=0&size=20"),
        api("/api/v1/assets?page=0&size=50")
    ]);
    render("scorecard-list", scorecards.content.map((item) =>
        `<div class="item"><strong>${item.metricKey} v${item.version}</strong><div>${item.effectiveFrom}</div><div class="item-meta">${item.definition}</div></div>`
    ));
    render("user-list", users.content.map((item) =>
        `<div class="item"><strong>${item.username}</strong><div>${item.email}</div><div class="item-meta">Contact ${item.contactInfo}</div></div>`
    ));
    render("admin-asset-list", assets.content.filter((asset) => asset.essential).map(renderAssetCard));
}

async function updateAssetState(assetId, operationalStatus, lifecycleState) {
    if (!assetId) {
        throw new Error("Choose an asset before submitting a state change.");
    }

    await api(`/api/v1/assets/${assetId}/status`, "PATCH", {
        status: operationalStatus,
        lifecycleState
    });

    await Promise.all([loadMaintenance(true), loadRequester(true), loadAdmin(true)]);
    setStatus("Asset state updated. Room availability and warnings refreshed.");
}

async function applyPromotionQuote() {
    const feedback = document.getElementById("booking-feedback");
    const promoCode = document.getElementById("reservation-promo").value.trim();
    const estimate = calculateReservationEstimate();

    if (!promoCode) {
        document.getElementById("booking-final").textContent = formatMoney(estimate);
        feedback.textContent = "No promotion code entered. Standard total shown.";
        return;
    }

    try {
        const result = await api("/api/v1/finance/promotions/apply", "POST", {
            code: promoCode,
            orderAmount: estimate,
            orderTime: new Date().toISOString()
        });
        document.getElementById("booking-final").textContent = formatMoney(Number(result.finalAmount));
        feedback.textContent = `Promotion ${promoCode} applied successfully.`;
    } catch (error) {
        document.getElementById("booking-final").textContent = formatMoney(estimate);
        feedback.textContent = error.message;
    }
}

async function api(url, method = "GET", body) {
    const headers = { "Content-Type": "application/json" };
    if (state.token) {
        headers.Authorization = `Bearer ${state.token}`;
    }
    return fetchJson(url, method, body, headers);
}

async function fetchJson(url, method, body, headers = { "Content-Type": "application/json" }) {
    const response = await fetch(url, {
        method,
        headers,
        body: body ? JSON.stringify(body) : undefined
    });

    if (response.status === 401) {
        logout();
        throw new Error("Unauthorized");
    }

    if (!response.ok) {
        const text = await response.text();
        try {
            const parsed = JSON.parse(text);
            throw new Error(parsed.message || `Request failed: ${response.status}`);
        } catch (error) {
            if (error instanceof SyntaxError) {
                throw new Error(text || `Request failed: ${response.status}`);
            }
            throw error;
        }
    }

    return response.status === 204 ? {} : response.json();
}

function render(id, chunks) {
    const target = document.getElementById(id);
    if (!target) {
        return;
    }
    target.innerHTML = chunks.join("") || "<div class=\"item\">No records yet.</div>";
}

function prependItem(id, chunk) {
    const target = document.getElementById(id);
    if (!target) {
        return;
    }
    if (target.innerHTML.includes("No records yet.")) {
        target.innerHTML = chunk;
        return;
    }
    target.innerHTML = chunk + target.innerHTML;
}

function titleForPanel(panelId) {
    return {
        requester: "Requester Workspace",
        frontdesk: "Front Desk Workspace",
        maintenance: "Maintenance Workspace",
        operations: "Operations Workspace",
        admin: "Administrator Workspace"
    }[panelId];
}

function setStatus(message) {
    const target = document.getElementById("load-status");
    if (target) {
        target.textContent = message;
    }
}

function logout() {
    localStorage.removeItem("eagle_token");
    localStorage.removeItem("eagle_username");
    localStorage.removeItem("eagle_roles");
    window.location.replace("/login.html");
}

function formatDateTime(value) {
    return new Date(value).toLocaleString();
}

function formatDate(value) {
    return new Date(value).toLocaleDateString();
}

function formatMoney(value) {
    return new Intl.NumberFormat(undefined, { style: "currency", currency: "USD" }).format(Number(value || 0));
}

function toUsDateString(value) {
    if (!value) {
        return "";
    }
    const [year, month, day] = value.split("-");
    if (!year || !month || !day) {
        return "";
    }
    return `${month}/${day}/${year}`;
}

function toIsoFromLocal(value) {
    if (!value) {
        return "";
    }
    return new Date(value).toISOString();
}

function extractRoles(token) {
    try {
        const payload = JSON.parse(atob(token.split(".")[1]));
        return Array.isArray(payload.roles) ? payload.roles.map((role) => role.replace("ROLE_", "")) : [];
    } catch (error) {
        return [];
    }
}

function allowedPanels() {
    if (state.roles.includes("ADMIN")) {
        return ["requester", "frontdesk", "maintenance", "operations", "admin"];
    }

    const panels = [];
    if (state.roles.includes("REQUESTER")) panels.push("requester");
    if (state.roles.includes("AGENT")) panels.push("frontdesk");
    if (state.roles.includes("TECH")) panels.push("maintenance");
    if (state.roles.includes("OPS")) panels.push("operations");
    return panels.length ? panels : ["requester"];
}

function defaultPanelForRoles() {
    return allowedPanels()[0];
}

function applyRoleVisibility() {
    const allowed = new Set(allowedPanels());
    document.querySelectorAll(".nav-btn").forEach((button) => {
        button.hidden = !allowed.has(button.dataset.panel);
    });
    document.querySelectorAll(".panel").forEach((panel) => {
        panel.hidden = !allowed.has(panel.id);
    });
}

function populateSelect(id, values, defaultLabel) {
    const target = document.getElementById(id);
    if (!target) {
        return;
    }
    target.innerHTML = values.map((value) => {
        if (!value) {
            return `<option value="">${defaultLabel}</option>`;
        }
        return `<option value="${escapeHtml(value)}">${escapeHtml(value)}</option>`;
    }).join("");
}

function populateAssetSelect(assets) {
    const target = document.getElementById("asset-id");
    if (!target) {
        return;
    }
    target.innerHTML = assets.map((asset) =>
        `<option value="${asset.id}">${escapeHtml(asset.name)} · Room ${escapeHtml(asset.roomNumber)} · ${escapeHtml(asset.lifecycleState)}</option>`
    ).join("");
}

function renderRoomCard(room) {
    const disabled = room.available ? "" : "disabled";
    const badgeClass = room.available ? "success-text" : "warning";
    const warningChunk = room.warning ? `<p class="warning">${escapeHtml(room.warning)}</p>` : "";

    return `<article class="workspace-card">
        <div class="item-meta">${escapeHtml(room.location)} · ${escapeHtml(room.roomType)}</div>
        <h3>${escapeHtml(room.roomNumber)}</h3>
        <p>Capacity ${room.capacity}</p>
        <p class="${badgeClass}">${escapeHtml(room.availabilityMessage || "Availability unknown.")}</p>
        ${warningChunk}
        <button class="primary-btn" data-room-select="${room.id}" ${disabled}>${room.available ? "Reserve This Room" : "Unavailable"}</button>
    </article>`;
}

function renderReservationItem(item) {
    const warning = item.roomWarning ? `<div class="warning">${escapeHtml(item.roomWarning)}</div>` : "";
    return `<div class="item">
        <strong>Room ${escapeHtml(item.roomNumber)}</strong>
        <div>${formatDateTime(item.startTime)} - ${formatDateTime(item.endTime)}</div>
        <div class="item-meta">${escapeHtml(item.status)}</div>
        ${warning}
    </div>`;
}

function renderAssetCard(asset) {
    const essential = asset.essential ? "Essential equipment" : "Standard asset";
    return `<div class="item">
        <strong>${escapeHtml(asset.name)}</strong>
        <div>Room ${escapeHtml(asset.roomNumber)} · ${escapeHtml(asset.assetType)}</div>
        <div class="${asset.lifecycleState === "UNDER_REPAIR" || asset.operationalStatus === "OUT_OF_SERVICE" ? "warning" : "item-meta"}">${escapeHtml(asset.operationalStatus)} · ${escapeHtml(asset.lifecycleState)} · ${essential}</div>
        <div class="action-row">
            <button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${asset.id}" data-operational-status="OUT_OF_SERVICE" data-lifecycle-state="UNDER_REPAIR">Set Under Repair</button>
            <button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${asset.id}" data-operational-status="IN_SERVICE" data-lifecycle-state="NORMAL">Restore</button>
            <button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${asset.id}" data-operational-status="${asset.operationalStatus}" data-lifecycle-state="RETIRED">Retire</button>
        </div>
    </div>`;
}

function selectRoom(roomId) {
    const room = state.roomsById.get(roomId);
    if (!room) {
        return;
    }

    document.getElementById("selected-room-id").value = String(room.id);
    document.getElementById("selected-room-label").value = `${room.roomNumber} · ${room.location} · Capacity ${room.capacity}`;
    syncReservationTimesFromFilters();
    refreshBookingEstimate();

    const feedback = document.getElementById("booking-feedback");
    feedback.textContent = room.available
        ? `Selected ${room.roomNumber}. You can book it now.`
        : room.availabilityMessage || "This room is not available for the chosen time.";
}

function syncReservationTimesFromFilters() {
    const filterStart = document.getElementById("filter-start");
    const filterEnd = document.getElementById("filter-end");
    const reservationStart = document.getElementById("reservation-start");
    const reservationEnd = document.getElementById("reservation-end");

    if (filterStart && reservationStart && filterStart.value) {
        reservationStart.value = filterStart.value;
    }
    if (filterEnd && reservationEnd && filterEnd.value) {
        reservationEnd.value = filterEnd.value;
    }
}

function seedRequesterTimes() {
    const start = document.getElementById("filter-start");
    const end = document.getElementById("filter-end");
    if (!start || !end || start.value || end.value) {
        return;
    }

    const now = new Date();
    now.setMinutes(Math.ceil(now.getMinutes() / 30) * 30, 0, 0);
    const later = new Date(now.getTime() + 60 * 60 * 1000);
    start.value = toLocalDateTimeValue(now);
    end.value = toLocalDateTimeValue(later);
}

function refreshBookingEstimate() {
    const estimate = calculateReservationEstimate();
    document.getElementById("booking-estimate").textContent = formatMoney(estimate);
    document.getElementById("booking-final").textContent = formatMoney(estimate);
}

function calculateReservationEstimate() {
    const startValue = document.getElementById("reservation-start").value;
    const endValue = document.getElementById("reservation-end").value;
    if (!startValue || !endValue) {
        return 0;
    }

    const hours = Math.max((new Date(endValue).getTime() - new Date(startValue).getTime()) / 3600000, 1);
    return Number((Math.ceil(hours * 2) / 2 * 75).toFixed(2));
}

function toLocalDateTimeValue(value) {
    const pad = (segment) => String(segment).padStart(2, "0");
    return `${value.getFullYear()}-${pad(value.getMonth() + 1)}-${pad(value.getDate())}T${pad(value.getHours())}:${pad(value.getMinutes())}`;
}

function escapeHtml(value) {
    return String(value ?? "")
        .replaceAll("&", "&amp;")
        .replaceAll("<", "&lt;")
        .replaceAll(">", "&gt;")
        .replaceAll("\"", "&quot;")
        .replaceAll("'", "&#39;");
}
