package com.eagle.app.controller;

import com.eagle.app.dto.RoomBrowserResponse;
import com.eagle.app.model.Room;
import com.eagle.app.repository.RoomRepository;
import com.eagle.app.repository.ReservationRepository;
import com.eagle.app.util.PaginationHeaderUtil;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageImpl;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.time.Instant;
import java.util.Comparator;
import java.util.List;
import java.util.Locale;

@RestController
@RequestMapping("/api/v1/catalog")
public class CatalogController {

    private final RoomRepository roomRepository;
    private final ReservationRepository reservationRepository;

    public CatalogController(RoomRepository roomRepository, ReservationRepository reservationRepository) {
        this.roomRepository = roomRepository;
        this.reservationRepository = reservationRepository;
    }

    @GetMapping("/rooms")
    public ResponseEntity<Page<RoomBrowserResponse>> rooms(@RequestParam(required = false) String location,
                                                           @RequestParam(required = false) String roomType,
                                                           @RequestParam(required = false) Integer minCapacity,
                                                           @RequestParam(required = false) Instant startTime,
                                                           @RequestParam(required = false) Instant endTime,
                                                           Pageable pageable) {
        List<RoomBrowserResponse> filtered = roomRepository.findAll(Pageable.unpaged()).stream()
                .filter(room -> matches(room.getLocation().getName(), location))
                .filter(room -> matches(room.getRoomType().getName(), roomType))
                .filter(room -> minCapacity == null || room.getCapacity() >= minCapacity)
                .sorted(Comparator.comparing(Room::getNumber))
                .map(room -> toAvailabilityResponse(room, startTime, endTime))
                .toList();

        int start = (int) pageable.getOffset();
        int end = Math.min(start + pageable.getPageSize(), filtered.size());
        List<RoomBrowserResponse> content = start >= filtered.size() ? List.of() : filtered.subList(start, end);
        Page<RoomBrowserResponse> page = new PageImpl<>(content, pageable, filtered.size());
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @GetMapping("/locations")
    public List<String> locations() {
        return roomRepository.findAll(Pageable.unpaged()).stream()
                .map(room -> room.getLocation().getName())
                .distinct()
                .sorted(Comparator.naturalOrder())
                .toList();
    }

    @GetMapping("/room-types")
    public List<String> roomTypes() {
        return roomRepository.findAll(Pageable.unpaged()).stream()
                .map(room -> room.getRoomType().getName())
                .distinct()
                .sorted(Comparator.naturalOrder())
                .toList();
    }

    private RoomBrowserResponse toAvailabilityResponse(Room room, Instant startTime, Instant endTime) {
        if (startTime == null || endTime == null) {
            return RoomBrowserResponse.from(room);
        }

        if (!room.isReservable()) {
            return RoomBrowserResponse.from(room, false,
                    room.getReservationWarning() != null ? room.getReservationWarning() : "Room is non-reservable.");
        }

        boolean conflict = reservationRepository.countConflicts(room.getId(), startTime, endTime) > 0;
        if (conflict) {
            return RoomBrowserResponse.from(room, false, "Conflicts with an existing reservation in the selected minute range.");
        }
        return RoomBrowserResponse.from(room, true, "Available for the selected date and time.");
    }

    private boolean matches(String actual, String filter) {
        if (filter == null || filter.isBlank()) {
            return true;
        }
        return actual.toLowerCase(Locale.ROOT).contains(filter.trim().toLowerCase(Locale.ROOT));
    }
}

