package com.eagle.app.controller;

import com.eagle.app.dto.ReservationRequest;
import com.eagle.app.dto.ReservationResponse;
import com.eagle.app.model.Reservation;
import com.eagle.app.model.ReservationStatus;
import com.eagle.app.repository.ReservationRepository;
import com.eagle.app.repository.RoomRepository;
import com.eagle.app.repository.UserRepository;
import com.eagle.app.service.ReservationService;
import com.eagle.app.util.PaginationHeaderUtil;
import java.security.Principal;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/v1/reservations")
public class ReservationController {

    private final ReservationRepository reservationRepository;
    private final ReservationService reservationService;
    private final UserRepository userRepository;
    private final RoomRepository roomRepository;

    public ReservationController(ReservationRepository reservationRepository,
                                 ReservationService reservationService,
                                 UserRepository userRepository,
                                 RoomRepository roomRepository) {
        this.reservationRepository = reservationRepository;
        this.reservationService = reservationService;
        this.userRepository = userRepository;
        this.roomRepository = roomRepository;
    }

    @GetMapping
    public ResponseEntity<Page<ReservationResponse>> list(Pageable pageable) {
        Page<ReservationResponse> page = reservationRepository.findAll(pageable).map(ReservationResponse::from);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @GetMapping("/mine")
    public ResponseEntity<Page<ReservationResponse>> mine(Pageable pageable, Principal principal) {
        var reservations = reservationRepository.findByRequester_UsernameOrderByStartTimeDesc(principal.getName())
                .stream()
                .map(ReservationResponse::from)
                .toList();
        int start = (int) pageable.getOffset();
        int end = Math.min(start + pageable.getPageSize(), reservations.size());
        var content = start >= reservations.size() ? java.util.List.<ReservationResponse>of() : reservations.subList(start, end);
        Page<ReservationResponse> page = new org.springframework.data.domain.PageImpl<>(content, pageable, reservations.size());
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public ReservationResponse create(@RequestBody ReservationRequest request, Principal principal) {
        Reservation reservation = new Reservation();
        if (request.requesterId() != null) {
            reservation.setRequester(userRepository.findById(request.requesterId())
                    .orElseThrow(() -> new IllegalArgumentException("Requester not found")));
        } else {
            reservation.setRequester(userRepository.findByUsername(principal.getName())
                    .orElseThrow(() -> new IllegalArgumentException("Requester not found")));
        }
        reservation.setRoom(roomRepository.findById(request.roomId())
                .orElseThrow(() -> new IllegalArgumentException("Room not found")));
        reservation.setStartTime(request.startTime());
        reservation.setEndTime(request.endTime());
        reservation.setStatus(request.status() == null ? ReservationStatus.PENDING : request.status());

        return ReservationResponse.from(reservationService.createReservation(reservation));
    }
}

