const state = {
    token: localStorage.getItem("eagle_token"),
    username: localStorage.getItem("eagle_username"),
    activePanel: "requester",
    loadedPanels: new Set(),
    roles: [],
    roomsById: new Map(),
    assetsById: new Map()
};

if (document.getElementById("login-form")) {
    initializeLoginPage();
}

if (document.querySelector(".dashboard-shell")) {
    initializeDashboard();
}

function initializeLoginPage() {
    if (state.token) {
        window.location.replace("/dashboard.html");
        return;
    }

    document.getElementById("login-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        const username = document.getElementById("username").value;
        const password = document.getElementById("password").value;
        const status = document.getElementById("session-status");
        status.textContent = "Authenticating...";

        try {
            const payload = await fetchJson("/api/v1/auth/login", "POST", { username, password });
            localStorage.setItem("eagle_token", payload.token);
            localStorage.setItem("eagle_username", username);
            localStorage.setItem("eagle_roles", JSON.stringify(extractRoles(payload.token)));
            window.location.replace("/dashboard.html");
        } catch (error) {
            status.textContent = error.message || "Authentication failed. Check your credentials and try again.";
        }
    });
}

function initializeDashboard() {
    if (!state.token) {
        window.location.replace("/login.html");
        return;
    }

    state.roles = extractRoles(state.token);
    document.getElementById("active-user").textContent = state.username || "workspace user";
    document.getElementById("logout-btn").addEventListener("click", logout);

    document.querySelectorAll(".nav-btn").forEach((button) => {
        button.addEventListener("click", async () => {
            await activatePanel(button.dataset.panel);
        });
    });

    wireForms();
    wireDelegatedActions();
    applyRoleVisibility();
    seedRequesterTimes();
    activatePanel(defaultPanelForRoles());
}

function wireForms() {
    const requesterFilterForm = document.getElementById("requester-filter-form");
    if (requesterFilterForm) {
        requesterFilterForm.addEventListener("submit", async (event) => {
            event.preventDefault();
            await loadRequester(true);
        });
    }

    ["filter-start", "filter-end", "reservation-start", "reservation-end", "reservation-promo"].forEach((id) => {
        const element = document.getElementById(id);
        if (!element) {
            return;
        }
        element.addEventListener("change", refreshBookingEstimate);
        element.addEventListener("input", refreshBookingEstimate);
    });

    const promoButton = document.getElementById("apply-promo-btn");
    if (promoButton) {
        promoButton.addEventListener("click", applyPromotionQuote);
    }

    const reservationForm = document.getElementById("reservation-form");
    if (reservationForm) {
        reservationForm.addEventListener("submit", async (event) => {
            event.preventDefault();
            const feedback = document.getElementById("booking-feedback");
            feedback.textContent = "";

            const roomId = Number(document.getElementById("selected-room-id").value);
            const start = document.getElementById("reservation-start").value;
            const end = document.getElementById("reservation-end").value;

            if (!roomId) {
                feedback.textContent = "Choose a room card first so we know what to reserve.";
                return;
            }
            if (!start || !end) {
                feedback.textContent = "Pick both reservation start and end using the calendar inputs.";
                return;
            }

            try {
                await api("/api/v1/reservations", "POST", {
                    roomId,
                    startTime: toIsoFromLocal(start),
                    endTime: toIsoFromLocal(end),
                    status: "APPROVED"
                });

                const promoCode = document.getElementById("reservation-promo").value.trim();
                if (promoCode) {
                    await applyPromotionQuote();
                }

                feedback.textContent = "Reservation created successfully.";
                const reloads = [loadRequester(true)];
                if (allowedPanels().includes("frontdesk")) {
                    reloads.push(loadFrontDesk(true));
                }
                await Promise.all(reloads);
                setStatus("Reservation created and workspace refreshed.");
            } catch (error) {
                feedback.textContent = error.message;
            }
        });
    }

    document.getElementById("banner-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        try {
            const saved = await api("/api/v1/frontdesk/banner-templates", "POST", {
                templateKey: document.getElementById("banner-key").value,
                minutesBefore: Number(document.getElementById("banner-minutes").value),
                message: document.getElementById("banner-message").value,
                active: true
            });
            prependItem("banner-list", `<div class="item"><strong>${saved.templateKey}</strong><div>${saved.minutesBefore} minutes before event</div><div class="item-meta">${saved.message}</div></div>`);
            setStatus("Banner template saved.");
        } catch (error) {
            setStatus(error.message);
        }
    });

    document.getElementById("handoff-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        try {
