    const availableRooms = rooms.filter((room) => room.available);
    const currentValue = target.value;
    if (!availableRooms.length) {
        target.innerHTML = `<option value="">No rooms available for this time</option>`;
        target.value = "";
        updateSelectedRoomLabel(null);
        return;
    }

    target.innerHTML = availableRooms.map((room) =>
        `<option value="${room.id}">${escapeHtml(room.roomNumber)} · ${escapeHtml(room.location)} · Capacity ${room.capacity}</option>`
    ).join("");

    const matchingRoom = availableRooms.find((room) => String(room.id) === currentValue) || availableRooms[0];
