@RestController
@RequestMapping("/api/v1/frontdesk")
public class FrontDeskController {

    private final ReservationRepository reservationRepository;
    private final BannerTemplateRepository bannerTemplateRepository;
    private final ShiftHandoffRepository shiftHandoffRepository;
    private final UserRepository userRepository;

    public FrontDeskController(ReservationRepository reservationRepository,
                               BannerTemplateRepository bannerTemplateRepository,
                               ShiftHandoffRepository shiftHandoffRepository,
                               UserRepository userRepository) {
        this.reservationRepository = reservationRepository;
        this.bannerTemplateRepository = bannerTemplateRepository;
        this.shiftHandoffRepository = shiftHandoffRepository;
        this.userRepository = userRepository;
    }

    @GetMapping("/schedule-board")
    public ResponseEntity<Page<ReservationResponse>> scheduleBoard(Pageable pageable) {
        Page<ReservationResponse> page = reservationRepository.findAll(pageable).map(ReservationResponse::from);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @GetMapping("/banner-templates")
    public ResponseEntity<Page<BannerTemplateResponse>> bannerTemplates(Pageable pageable) {
        Page<BannerTemplateResponse> page = bannerTemplateRepository.findAll(pageable).map(BannerTemplateResponse::from);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @PostMapping("/banner-templates")
    public BannerTemplate saveBannerTemplate(@RequestBody BannerTemplateRequest request) {
        BannerTemplate template = bannerTemplateRepository.findByTemplateKey(request.templateKey())
                .orElseGet(BannerTemplate::new);
        template.setTemplateKey(request.templateKey());
        template.setMinutesBefore(request.minutesBefore());
        template.setMessage(request.message());
        template.setActive(request.active());
        return bannerTemplateRepository.save(template);
    }

    @GetMapping("/shift-handoffs")
    public ResponseEntity<Page<ShiftHandoffResponse>> shiftHandoffs(Pageable pageable) {
        Page<ShiftHandoffResponse> page = shiftHandoffRepository.findAll(pageable).map(ShiftHandoffResponse::from);
        HttpHeaders headers = new HttpHeaders();
        PaginationHeaderUtil.applyPrefetchHint(headers, page);
        return new ResponseEntity<>(page, headers, HttpStatus.OK);
    }

    @PostMapping("/shift-handoffs")
    public ShiftHandoffResponse saveShiftHandoff(@RequestBody ShiftHandoffRequest request) {
        ShiftHandoff handoff = new ShiftHandoff();
        handoff.setFromUser(userRepository.findById(request.fromUserId()).orElseThrow(() -> new IllegalArgumentException("from user not found")));
        handoff.setToUser(userRepository.findById(request.toUserId()).orElseThrow(() -> new IllegalArgumentException("to user not found")));
        handoff.setHandoffTime(request.handoffTime());
        handoff.setSummary(request.summary());
        handoff.setPendingTasks(request.pendingTasks());
        return ShiftHandoffResponse.from(shiftHandoffRepository.save(handoff));
    }
}

