{"command":"$path = 'C:\Users\Tad\Desktop\EagleAI\EaglePt\fullstack3\app\backend\src\main\resources\static\app.js';
$content = Get-Content -Path $path -Raw;
$oldLoadFrontDesk = @'
async function loadFrontDesk() {
    const [schedule, banners, handoffs] = await Promise.all([
        api("/api/v1/frontdesk/schedule-board?page=0&size=20"),
        api("/api/v1/frontdesk/banner-templates?page=0&size=20"),
        api("/api/v1/frontdesk/shift-handoffs?page=0&size=20")
    ]);

    render("schedule-board", schedule.content.map((item) =>
        `<div class="item"><strong>Room ${item.roomId}</strong><div>${formatDateTime(item.startTime)} - ${formatDateTime(item.endTime)}</div><div class="item-meta">${item.status}</div></div>`
    ));
    render("banner-list", banners.content.map((item) =>
        `<div class="item"><strong>${item.templateKey}</strong><div>${item.minutesBefore} minutes before event</div><div class="item-meta">${item.message}</div></div>`
    ));
    render("handoff-list", handoffs.content.map((item) =>
        `<div class="item"><strong>${item.fromUser} to ${item.toUser}</strong><div>${item.summary}</div><div class="item-meta">${item.pendingTasks || "No pending tasks"}</div></div>`
    ));
}
'@;
$newLoadFrontDesk = @'
async function loadFrontDesk() {
    const params = new URLSearchParams({ page: "0", size: "50" });
    const room = document.getElementById("schedule-room-filter")?.value?.trim();
    const status = document.getElementById("schedule-status-filter")?.value;
    const from = document.getElementById("schedule-from-filter")?.value;
    const to = document.getElementById("schedule-to-filter")?.value;
    if (room) params.set("room", room);
    if (status) params.set("status", status);
    if (from) params.set("from", toIsoFromLocal(from));
    if (to) params.set("to", toIsoFromLocal(to));

    const [schedule, banners, handoffs, notifications, agents] = await Promise.all([
        api(`/api/v1/frontdesk/schedule-board?${params.toString()}`),
        api("/api/v1/frontdesk/banner-templates?page=0&size=20"),
        api("/api/v1/frontdesk/shift-handoffs?page=0&size=20"),
        api("/api/v1/frontdesk/notifications?page=0&size=50"),
        api("/api/v1/frontdesk/agents")
    ]);

    populateAgentSelects(agents);
    render("schedule-board", schedule.content.map(renderScheduleItem));
    render("banner-list", banners.content.map(renderBannerTemplateItem));
    render("handoff-list", handoffs.content.map(renderHandoffItem));

    const activeBanners = notifications.content.filter((item) => item.status === "PROCESSED");
    const historicalBanners = notifications.content.filter((item) => item.status === "DISMISSED");
    render("active-banner-list", activeBanners.map(renderActiveBannerItem));
    render("notification-history-list", historicalBanners.map(renderNotificationHistoryItem));
}
'@;
$content = $content.Replace($oldLoadFrontDesk, $newLoadFrontDesk);
$oldWireDelegated = @'
function wireDelegatedActions() {
    document.addEventListener("click", async (event) => {
        const roomButton = event.target.closest("[data-room-select]");
        if (roomButton) {
            selectRoom(Number(roomButton.dataset.roomSelect));
            return;
        }

        const assetButton = event.target.closest("[data-asset-action]");
        if (assetButton) {
            try {
                await updateAssetState(
                    Number(assetButton.dataset.assetId),
                    assetButton.dataset.operationalStatus,
                    assetButton.dataset.lifecycleState
                );
            } catch (error) {
                setStatus(error.message);
                showToast(error.message, "error");
            }
        }
    });
}
'@;
$newWireDelegated = @'
function wireDelegatedActions() {
    document.addEventListener("click", async (event) => {
        const roomButton = event.target.closest("[data-room-select]");
        if (roomButton) {
            selectRoom(Number(roomButton.dataset.roomSelect));
            return;
        }

        const templateButton = event.target.closest("[data-template-edit]");
        if (templateButton) {
            document.getElementById("banner-key").value = templateButton.dataset.templateKey;
            document.getElementById("banner-minutes").value = templateButton.dataset.minutesBefore;
            document.getElementById("banner-message").value = templateButton.dataset.message;
            showToast(`Loaded ${templateButton.dataset.templateKey} into the editor.`, "success");
            return;
        }

        const reservationAction = event.target.closest("[data-reservation-action]");
        if (reservationAction) {
            try {
                const reservationId = Number(reservationAction.dataset.reservationId);
                const action = reservationAction.dataset.reservationAction;
                const endpoint = action === "confirm" ? "confirm-arrival" : "checkout";
                await api(`/api/v1/frontdesk/reservations/${reservationId}/${endpoint}`, "POST");
                await loadFrontDesk(true);
                showToast(action === "confirm" ? "Arrival confirmed." : "Checkout completed.", "success");
            } catch (error) {
                showToast(error.message, "error");
            }
            return;
        }

        const dismissButton = event.target.closest("[data-banner-dismiss]");
        if (dismissButton) {
            try {
                await api(`/api/v1/frontdesk/notifications/${dismissButton.dataset.bannerDismiss}/dismiss`, "POST");
                await loadFrontDesk(true);
                showToast("Banner dismissed.", "success");
            } catch (error) {
                showToast(error.message, "error");
            }
            return;
        }

        const assetButton = event.target.closest("[data-asset-action]");
        if (assetButton) {
            try {
                await updateAssetState(
                    Number(assetButton.dataset.assetId),
                    assetButton.dataset.operationalStatus,
                    assetButton.dataset.lifecycleState
                );
                showToast("Asset state updated.", "success");
            } catch (error) {
                setStatus(error.message);
                showToast(error.message, "error");
            }
        }
    });
}
'@;
$content = $content.Replace($oldWireDelegated, $newWireDelegated);
Set-Content -Path $path -Value $content -Encoding utf8;","workdir":"C:\Users\Tad\Desktop\EagleAI\EaglePt\fullstack3","timeout_ms":10000}

