#[rocket::async_trait]
impl<'r> FromRequest<'r> for AuthUser {
    type Error = String;

    async fn from_request(req: &'r Request<'_>) -> Outcome<Self, Self::Error> {
        let Some(state) = req.rocket().state::<AppState>() else {
            return Outcome::Error((Status::InternalServerError, "missing app state".into()));
        };

        let auth_header = req.headers().get_one("Authorization").map(str::to_owned);
        let jar = req.cookies();

        if let Some(header) = auth_header {
            if let Some(token) = header.strip_prefix("Bearer ") {
                let key = DecodingKey::from_secret(state.jwt_secret.as_bytes());
                let mut validation = Validation::new(Algorithm::HS256);
                validation.validate_exp = true;
                let claims = match decode::<Claims>(token, &key, &validation) {
                    Ok(c) => c.claims,
                    Err(_) => return Outcome::Error((Status::Unauthorized, "invalid token".into())),
                };
                return Outcome::Success(AuthUser {
                    username: claims.sub,
                    role: claims.role,
                });
            }
        }

        let Some(cookie) = jar.get("proctorops_session") else {
            return Outcome::Error((Status::Unauthorized, "missing authentication".into()));
        };

        let session_id = cookie.value().to_owned();
        let mut d = state.data.write().await;
        let Some(session_state) = d.session_store.get_mut(&session_id) else {
            return Outcome::Error((Status::Unauthorized, "invalid session".into()));
        };

        if Utc::now() - session_state.last_seen > Duration::minutes(SESSION_IDLE_MINUTES) {
            d.session_store.remove(&session_id);
            return Outcome::Error((Status::Unauthorized, "session expired".into()));
        }

        session_state.last_seen = Utc::now();
        Outcome::Success(AuthUser {
            username: session_state.username.clone(),
            role: session_state.role,
        })
    }
}

