    private final AnnouncementRepository announcements;
    private final AttachmentModerationItemRepository moderation;
    private final UserRepository users;

    public OperationsController(PromotionRepository promotions, AnnouncementRepository announcements,
                                AttachmentModerationItemRepository moderation, UserRepository users) {
        this.promotions = promotions;
        this.announcements = announcements;
        this.moderation = moderation;
        this.users = users;
    }

    @GetMapping("/promotions")
    public Page<Promotion> listPromotions(Pageable pageable) { return promotions.findAll(pageable); }

