    @GetMapping("/announcements")
    public Page<Announcement> listAnnouncements(Pageable pageable) { return announcements.findAll(pageable); }

    @PostMapping("/announcements")
    public Announcement saveAnnouncement(@RequestBody AnnouncementRequest req) {
        Announcement a = new Announcement();
        a.title = req.title();
        a.message = req.message();
        a.published = req.published();
        return announcements.save(a);
    }

    @GetMapping("/moderation-queue")
    public Page<AttachmentModerationItem> listModeration(Pageable pageable) { return moderation.findAll(pageable); }

    @PostMapping("/moderation-queue")
    public AttachmentModerationItem saveModeration(@RequestBody ModerationRequest req) {
        AttachmentModerationItem i = new AttachmentModerationItem();
        i.fileName = req.fileName();
        i.contentType = req.contentType();
        i.status = req.status();
        i.reason = req.reason();
        if (req.uploadedById() != null) {
            i.uploadedBy = users.findById(req.uploadedById()).orElse(null);
        }
        return moderation.save(i);
    }
