.item,.workspace-card { padding: 16px; margin-bottom: 12px; border-radius: 20px; background: rgba(255,255,255,.88); border: 1px solid rgba(18,32,51,.07); }
.warning { color: var(--danger); font-weight: 700; }
.success-text { color: var(--accent-cool); font-weight: 700; }
.workspace-summary,.action-row { display: flex; gap: 12px; flex-wrap: wrap; }
.workspace-summary { padding: 14px 16px; border-radius: 18px; background: rgba(18,32,51,.05); justify-content: space-between; }
.checkbox-row { display: flex; gap: 18px; flex-wrap: wrap; font-weight: 600; }
.checkbox-row label { display: inline-flex; align-items: center; gap: 8px; }
.checkbox-row input[type="checkbox"] { width: auto; }
.toast-container { position: fixed; top: 24px; right: 24px; display: grid; gap: 10px; z-index: 9999; }
