.toast-success { background: rgba(13,148,136,.92); }
.toast-error { background: rgba(185,28,28,.94); }
.toast-hide { opacity: 0; transform: translateY(-6px); }
@media (max-width: 1100px) {
  .auth-shell,.dashboard-shell,.workspace-columns.two,.workspace-columns.three,.inline-stack,.weights-grid { grid-template-columns: 1fr; }
  .topbar { align-items: flex-start; flex-direction: column; gap: 14px; }
}
