async function loadOperations() {
  const [promotions, announcements, moderation] = await Promise.all([
    api("/api/v1/operations/promotions?page=0&size=20"),
    api("/api/v1/operations/announcements?page=0&size=20"),
    api("/api/v1/operations/moderation-queue?page=0&size=20")
  ]);
  render("promotion-list", promotions.content.map((p) => `<div class="item"><strong>${p.code}</strong><div>${p.promotionType}</div><div class="item-meta">${p.percentage}% active discount</div></div>`));
  render("announcement-list", announcements.content.map((a) => `<div class="item"><strong>${a.title}</strong><div>${a.message}</div></div>`));
  render("moderation-list", moderation.content.map((m) => `<div class="item"><strong>${m.fileName}</strong><div>${m.status}</div><div class="item-meta">${m.reason || "Awaiting review notes"}</div></div>`));
}

async function loadAdmin() {
  const [scorecards, users, assets, rooms] = await Promise.all([
    api("/api/v1/metrics/scorecards?page=0&size=20"),
    api("/api/v1/users?page=0&size=20"),
    api("/api/v1/assets?page=0&size=50"),
    api("/api/v1/catalog/rooms?page=0&size=50")
  ]);
  render("scorecard-list", scorecards.content.map((s) => `<div class="item"><strong>${s.metricKey} v${s.version}</strong><div>${s.effectiveFrom}</div><div class="item-meta">${s.definition}</div></div>`));
  render("user-list", users.content.map((u) => `<div class="item"><strong>${u.username}</strong><div>${u.email}</div><div class="item-meta">Contact ${u.contactInfo}</div></div>`));
  render("admin-room-list", rooms.content.map(renderRoomCard));
  render("admin-asset-list", assets.content.filter((a) => a.essential).map(renderAssetCard));
}

async function updateAssetState(assetId, operationalStatus, lifecycleState) {
  if (!assetId) throw new Error("Choose an asset before submitting a state change.");
  await api(`/api/v1/assets/${assetId}/status`, "PATCH", { status: operationalStatus, lifecycleState });
  const reloads = [loadMaintenance(true), loadRequester(true)];
  if (state.roles.includes("ADMIN")) reloads.push(loadAdmin(true));
  await Promise.all(reloads);
}

async function applyPromotionQuote() {
  const code = byId("reservation-promo").value.trim();
  const estimate = calculateEstimate();
  if (!code) {
    byId("booking-final").textContent = formatMoney(estimate);
    return;
  }
  try {
    const result = await api("/api/v1/finance/promotions/apply", "POST", { code, orderAmount: estimate, orderTime: new Date().toISOString() });
    byId("booking-final").textContent = formatMoney(Number(result.finalAmount));
    showLocalFeedback("booking-feedback", `Promotion ${code} applied successfully.`);
  } catch (error) {
    byId("booking-final").textContent = formatMoney(estimate);
    showLocalFeedback("booking-feedback", error.message);
    showToast(error.message, "error");
  }
}

async function api(url, method = "GET", body) {
  const headers = { "Content-Type": "application/json" };
  if (state.token) headers.Authorization = `Bearer ${state.token}`;
  return fetchJson(url, method, body, headers);
}

async function fetchJson(url, method, body, headers = { "Content-Type": "application/json" }) {
  const response = await fetch(url, { method, headers, body: body ? JSON.stringify(body) : undefined });
  if (response.status === 401) {
    logout();
    throw new Error("Unauthorized");
  }
  if (!response.ok) {
    const text = await response.text();
    try {
      const parsed = JSON.parse(text);
      throw new Error(parsed.message || `Request failed: ${response.status}`);
    } catch (error) {
      if (error instanceof SyntaxError) throw new Error(text || `Request failed: ${response.status}`);
      throw error;
    }
  }
  return response.status === 204 ? {} : response.json();
}

function render(id, rows) {
  const target = byId(id);
  if (!target) return;
  target.innerHTML = rows.join("") || '<div class="item">No records yet.</div>';
}

function prependItem(id, row) {
  const target = byId(id);
  if (!target) return;
  if (target.innerHTML.includes("No records yet.")) target.innerHTML = row;
  else target.innerHTML = row + target.innerHTML;
}

function populateSelect(id, values, defaultLabel) {
  const target = byId(id);
  if (!target) return;
  target.innerHTML = values.map((v) => (v ? `<option value="${escapeHtml(v)}">${escapeHtml(v)}</option>` : `<option value="">${defaultLabel}</option>`)).join("");
}

function populateReservationRoomSelect(rooms) {
  const target = byId("selected-room-id");
  if (!target) return;
  const available = rooms.filter((r) => r.available);
  const current = target.value;
  if (!available.length) {
    target.innerHTML = '<option value="">No rooms available for this time</option>';
    target.value = "";
    updateSelectedRoomLabel(null);
    return;
  }
  target.innerHTML = available.map((r) => `<option value="${r.id}">${escapeHtml(r.roomNumber)} - ${escapeHtml(r.location)} - Capacity ${r.capacity}</option>`).join("");
  const pick = available.find((r) => String(r.id) === current) || available[0];
  target.value = String(pick.id);
  updateSelectedRoomLabel(pick);
}

function populateAgentSelects(agents) {
  const from = byId("handoff-from");
  const to = byId("handoff-to");
  if (!from || !to) return;
  const options = agents.map((a) => `<option value="${a.id}">${escapeHtml(a.username)}</option>`).join("");
  from.innerHTML = options;
  to.innerHTML = options;
}

function populateAssetSelect(assets) {
  const target = byId("asset-id");
  if (!target) return;
  target.innerHTML = assets.map((a) => `<option value="${a.id}">${escapeHtml(a.name)} - Room ${escapeHtml(a.roomNumber)} - ${escapeHtml(a.lifecycleState)}</option>`).join("");
}

function renderRoomCard(room) {
  const disabled = room.available ? "" : "disabled";
  const cls = room.available ? "success-text" : "warning";
  return `<article class="workspace-card"><div class="item-meta">${escapeHtml(room.location)} - ${escapeHtml(room.roomType)}</div><h3>${escapeHtml(room.roomNumber)}</h3><p>Capacity ${room.capacity}</p><p class="${cls}">${escapeHtml(room.availabilityMessage || "Availability unknown.")}</p>${room.warning ? `<p class="warning">${escapeHtml(room.warning)}</p>` : ""}<button class="primary-btn" data-room-select="${room.id}" ${disabled}>${room.available ? "Reserve This Room" : "Unavailable"}</button></article>`;
}

function renderReservationItem(r) {
  return `<div class="item"><strong>Room ${escapeHtml(r.roomNumber)}</strong><div>${formatDateTime(r.startTime)} - ${formatDateTime(r.endTime)}</div><div class="item-meta">${escapeHtml(r.status)}</div>${r.roomWarning ? `<div class="warning">${escapeHtml(r.roomWarning)}</div>` : ""}</div>`;
}

function renderScheduleItem(item) {
  const actions = [];
  if (item.status === "PENDING" || item.status === "APPROVED") actions.push(`<button type="button" class="ghost-accent-btn" data-reservation-action="confirm" data-reservation-id="${item.id}">Confirm Arrival</button>`);
  if (item.status === "CHECKED_IN") actions.push(`<button type="button" class="ghost-accent-btn" data-reservation-action="checkout" data-reservation-id="${item.id}">Checkout</button>`);
  const statusClass = item.status === "CHECKED_IN" ? "success-text" : (item.status === "PENDING" ? "warning" : "item-meta");
  return `<div class="item"><strong>Room ${escapeHtml(item.roomNumber)}</strong><div>${formatDateTime(item.startTime)} - ${formatDateTime(item.endTime)}</div><div class="item-meta">Guest ${escapeHtml(item.requesterUsername || "")}</div><div class="${statusClass}">${escapeHtml(item.status)}</div><div class="item-meta">Checked in: ${item.checkedInAt ? formatDateTime(item.checkedInAt) : "Not yet"}</div><div class="item-meta">Checked out: ${item.checkedOutAt ? formatDateTime(item.checkedOutAt) : "Not yet"}</div><div class="action-row">${actions.join("")}</div></div>`;
}

function renderBannerTemplateItem(t) {
  return `<div class="item"><strong>${escapeHtml(t.templateKey)}</strong><div>${t.minutesBefore} minutes before event</div><div class="item-meta">${escapeHtml(t.message)}</div><div class="action-row"><button type="button" class="ghost-accent-btn" data-template-edit="true" data-template-key="${escapeHtml(t.templateKey)}" data-minutes-before="${t.minutesBefore}" data-message="${escapeHtml(t.message)}">Edit Template</button></div></div>`;
}

function renderHandoffItem(h) {
  return `<div class="item"><strong>${escapeHtml(h.fromUser)} to ${escapeHtml(h.toUser)}</strong><div>${escapeHtml(h.summary)}</div><div class="item-meta">${formatDateTime(h.handoffTime)}</div><div class="warning">${escapeHtml(h.pendingTasks || "No unresolved tasks")}</div></div>`;
}

function renderActiveBannerItem(b) {
  return `<div class="item"><strong>${escapeHtml(b.templateKey)}</strong><div>${escapeHtml(b.message)}</div><div class="item-meta">Room ${escapeHtml(b.roomNumber)} - ${escapeHtml(b.requesterUsername)} - ${formatDateTime(b.scheduledFor)}</div><div class="action-row"><button type="button" class="ghost-accent-btn" data-banner-dismiss="${b.id}">Dismiss Banner</button></div></div>`;
}

function renderNotificationHistoryItem(b) {
  return `<div class="item"><strong>${escapeHtml(b.templateKey)}</strong><div>${escapeHtml(b.message)}</div><div class="item-meta">${escapeHtml(b.status)} - Room ${escapeHtml(b.roomNumber)} - ${formatDateTime(b.scheduledFor)}</div><div class="item-meta">Dismissed: ${b.dismissedAt ? formatDateTime(b.dismissedAt) : "Not dismissed"}</div></div>`;
}

function renderAssetCard(a) {
  const essential = a.essential ? "Essential equipment" : "Standard asset";
  return `<div class="item"><strong>${escapeHtml(a.name)}</strong><div>Room ${escapeHtml(a.roomNumber)} - ${escapeHtml(a.assetType)}</div><div class="${a.lifecycleState === "UNDER_REPAIR" || a.operationalStatus === "OUT_OF_SERVICE" ? "warning" : "item-meta"}">${escapeHtml(a.operationalStatus)} - ${escapeHtml(a.lifecycleState)} - ${essential}</div><div class="action-row"><button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${a.id}" data-operational-status="OUT_OF_SERVICE" data-lifecycle-state="UNDER_REPAIR">Set Under Repair</button><button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${a.id}" data-operational-status="IN_SERVICE" data-lifecycle-state="NORMAL">Restore</button><button type="button" class="ghost-accent-btn" data-asset-action="true" data-asset-id="${a.id}" data-operational-status="${a.operationalStatus}" data-lifecycle-state="RETIRED">Retire</button></div></div>`;
}

function selectRoom(id) {
  const room = state.roomsById.get(id);
  if (!room) return;
  byId("selected-room-id").value = String(room.id);
  updateSelectedRoomLabel(room);
  syncReservationTimes();
  refreshBookingEstimate();
  showLocalFeedback("booking-feedback", room.available ? `Selected ${room.roomNumber}. You can book it now.` : room.availabilityMessage || "This room is unavailable.");
}

function updateSelectedRoomLabel(room) {
  const t = byId("selected-room-label");
  if (!t) return;
  t.textContent = !room ? "Choose an available room from the filtered list." : `${room.roomNumber} - ${room.location} - ${room.roomType} - Capacity ${room.capacity}`;
}

function syncReservationTimes() {
  if (byId("filter-start").value) byId("reservation-start").value = byId("filter-start").value;
  if (byId("filter-end").value) byId("reservation-end").value = byId("filter-end").value;
}

function seedTimes() {
  if (!byId("filter-start").value || !byId("filter-end").value) {
    const now = new Date();
    now.setMinutes(Math.ceil(now.getMinutes() / 30) * 30, 0, 0);
    const later = new Date(now.getTime() + 3600000);
    byId("filter-start").value = toLocalDateTime(now);
    byId("filter-end").value = toLocalDateTime(later);
  }
  if (!byId("schedule-from-filter").value || !byId("schedule-to-filter").value) {
    const start = new Date(); start.setHours(0,0,0,0);
    const end = new Date(); end.setHours(23,59,0,0);
    byId("schedule-from-filter").value = toLocalDateTime(start);
    byId("schedule-to-filter").value = toLocalDateTime(end);
  }
  if (!byId("effective-from").value) byId("effective-from").value = new Date().toISOString().slice(0, 10);
}

function refreshBookingEstimate() {
  const room = state.roomsById.get(Number(byId("selected-room-id")?.value));
  if (room) updateSelectedRoomLabel(room);
  const estimate = calculateEstimate();
  byId("booking-estimate").textContent = formatMoney(estimate);
  byId("booking-final").textContent = formatMoney(estimate);
}

function calculateEstimate() {
  const s = byId("reservation-start").value;
  const e = byId("reservation-end").value;
  if (!s || !e) return 0;
  const hours = Math.max((new Date(e).getTime() - new Date(s).getTime()) / 3600000, 1);
  return Number((Math.ceil(hours * 2) / 2 * 75).toFixed(2));
}

function showToast(message, type) {
  if (!message) return;
  let container = byId("toast-container");
  if (!container) {
    container = document.createElement("div");
    container.id = "toast-container";
    container.className = "toast-container";
    document.body.appendChild(container);
  }
  const toast = document.createElement("div");
  toast.className = `toast toast-${type || "success"}`;
  toast.textContent = message;
  container.appendChild(toast);
  setTimeout(() => {
    toast.classList.add("toast-hide");
    setTimeout(() => toast.remove(), 250);
  }, 4000);
}

function showLocalFeedback(id, message) { const t = byId(id); if (t) t.textContent = message; }
function setStatus(text) { const t = byId("load-status"); if (t) t.textContent = text; }
function logout() { localStorage.removeItem("eagle_token"); localStorage.removeItem("eagle_username"); localStorage.removeItem("eagle_roles"); window.location.replace("/login.html"); }
function byId(id) { return document.getElementById(id); }
function titleFor(id) { return { requester: "Requester Workspace", frontdesk: "Front Desk Workspace", maintenance: "Maintenance Workspace", operations: "Operations Workspace", admin: "Administrator Workspace" }[id]; }
function toUsDateString(value) { if (!value) return ""; const [y, m, d] = value.split("-"); return `${m}/${d}/${y}`; }
function toIsoFromLocal(value) { return new Date(value).toISOString(); }
function formatDateTime(value) { return new Date(value).toLocaleString(); }
function formatDate(value) { return new Date(value).toLocaleDateString(); }
function formatMoney(v) { return new Intl.NumberFormat(undefined, { style: "currency", currency: "USD" }).format(Number(v || 0)); }
function toLocalDateTime(d) { const p = (x) => String(x).padStart(2, "0"); return `${d.getFullYear()}-${p(d.getMonth() + 1)}-${p(d.getDate())}T${p(d.getHours())}:${p(d.getMinutes())}`; }
function escapeHtml(v) { return String(v ?? "").replaceAll("&", "&amp;").replaceAll("<", "&lt;").replaceAll(">", "&gt;").replaceAll("\"", "&quot;").replaceAll("'", "&#39;"); }

function extractRoles(token) {
  try {
    const encoded = token.split(".")[1].replace(/-/g, "+").replace(/_/g, "/");
    const padded = encoded.padEnd(Math.ceil(encoded.length / 4) * 4, "=");
    const payload = JSON.parse(atob(padded));
    return Array.isArray(payload.roles) ? payload.roles.map((r) => r.replace("ROLE_", "")) : [];
  } catch (_e) {
    return [];
  }
}

function allowedPanels() {
  if (state.roles.includes("ADMIN")) return ["requester", "frontdesk", "maintenance", "operations", "admin"];
  const p = [];
  if (state.roles.includes("REQUESTER")) p.push("requester");
  if (state.roles.includes("AGENT")) p.push("frontdesk");
  if (state.roles.includes("TECH")) p.push("maintenance");
  if (state.roles.includes("OPS")) p.push("operations");
  return p.length ? p : ["requester"];
}

function defaultPanelForRoles() { return allowedPanels()[0]; }
function applyRoleVisibility() {
  const allowed = new Set(allowedPanels());
  document.querySelectorAll(".nav-btn").forEach((b) => { b.hidden = !allowed.has(b.dataset.panel); });
  document.querySelectorAll(".panel").forEach((p) => { p.hidden = !allowed.has(p.id); });
}
